designs.type_sketch:
// Make 'construct -> running counter' hold the way PWM's configure self-enables
// its clock tree. TCXO has NO separate CKEN register (notes: gated solely by
// tcxo_status.enable), so self-enabling in new() IS the clock-gate change.
//
// Phantom type-state encodes whether the run-gate is up, so only a Running driver
// exposes read_counter(). The default constructor self-enables (matches vendor
// hal_tcxo_init order: set_enable THEN set_clear).
pub struct Enabled;   // counter free-running (enable bit set)
pub struct Disabled;  // explicit low-power / parked state

pub struct TcxoDriver<'d, S = Enabled> {
    _tcxo: Tcxo<'d>,
    _state: PhantomData<S>,
}

impl<'d> TcxoDriver<'d, Enabled> {
    /// Construct and bring the counter up: set enable (bit 2) THEN clear (bit 1),
    /// exactly like vendor hal_tcxo_init. After this the counter is guaranteed
    /// free-running and zero-based.
    pub fn new(tcxo: Tcxo<'d>) -> Self {
        let me = TcxoDriver { _tcxo: tcxo, _state: PhantomData };
        let regs = unsafe { &*Tcxo::ptr() };
        let s = regs.tcxo_status().read().bits();
        unsafe { regs.tcxo_status().write(|w| w.bits(s | TCXO_EN_BIT)); }   // enable
        let s = regs.tcxo_status().read().bits();
        unsafe { regs.tcxo_status().write(|w| w.bits(s | TCXO_CLEAR_BIT)); } // clear
        me
    }
}

impl<'d> TcxoDriver<'d, Enabled> {
    pub fn read_counter(&self) -> Option<u64> { /* refresh + read, see defect 3 */ }
    pub fn read_counter32(&self) -> Option<u32> { /* ... */ }
    /// Park the counter (clears enable); read_counter no longer callable.
    pub fn disable(self) -> TcxoDriver<'d, Disabled> { /* clear EN_BIT */ }
}
impl<'d> TcxoDriver<'d, Disabled> {
    pub fn enable(self) -> TcxoDriver<'d, Enabled> { /* set EN_BIT + CLEAR_BIT */ }
}
// read_counter is NOT implemented for Disabled => a frozen-counter read is
// unrepresentable at the type level (the class-C precondition is enforced).

// Folded into the same new() as defect 1 — vendor does set_enable() THEN
// set_clear() in one init (hal_tcxo_v150.c:28). Issuing the clear gives a
// defined zero origin for the documented t0/elapsed use case.
impl<'d> TcxoDriver<'d, Enabled> {
    pub fn new(tcxo: Tcxo<'d>) -> Self {
        // ... set TCXO_EN_BIT (defect 1) ...
        let s = regs.tcxo_status().read().bits();
        unsafe { regs.tcxo_status().write(|w| w.bits(s | TCXO_CLEAR_BIT)); } // bit 1
        // counter now zero-based
    }
    /// Re-zero the counter origin without dropping the driver.
    pub fn clear(&mut self) {
        let s = self.regs().tcxo_status().read().bits();
        unsafe { self.regs().tcxo_status().write(|w| w.bits(s | TCXO_CLEAR_BIT)); }
    }
}

// Stop bypassing the PAC's 16-bit-masked accessor. The PAC already provides
// tcxo_countN().read().countN() -> FieldReader<u16> = (bits & 0xffff) as u16
// (ws63-pac/src/lib.rs:29406-29512). Use it so each lane is mask-guaranteed
// 16-bit and an undefined upper half can never bleed into the next lane.
pub fn read_counter(&self) -> Option<u64> {
    self.refresh().ok()?;
    let r = self.regs();
    let c0 = r.tcxo_count0().read().count0() as u64; // masked &0xffff in the PAC
    let c1 = r.tcxo_count1().read().count1() as u64;
    let c2 = r.tcxo_count2().read().count2() as u64;
    let c3 = r.tcxo_count3().read().count3() as u64;
    Some((c3 << 48) | (c2 << 32) | (c1 << 16) | c0)
}
pub fn read_counter32(&self) -> Option<u32> {
    self.refresh().ok()?;
    let r = self.regs();
    let c0 = r.tcxo_count0().read().count0() as u32;
    let c1 = r.tcxo_count1().read().count1() as u32;
    Some((c1 << 16) | c0)
}
// Belt-and-suspenders if the masked accessor is ever unavailable: mask inline
//   let c0 = (r.tcxo_count0().read().bits() & 0xFFFF) as u64;
// The existing proptests already feed u16 lanes, so they keep passing unchanged.

// Replace the magic 100 with a validated, documented spin budget whose rationale
// is tied to the REAL clock (24MHz, or 40MHz selectable), not the wrong 32kHz.
// Newtype so a 0-iteration budget (which would never poll) is unrepresentable,
// mirroring PwmPeriod's non-zero invariant.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct RefreshTimeout(u32); // spin-loop iterations, >= 1
impl RefreshTimeout {
    /// Vendor budget: TCXO_LOCK_GET_ATTE = 0xFFFFFFFF (tcxo_porting.h:29).
    pub const VENDOR_MAX: RefreshTimeout = RefreshTimeout(0xFFFF_FFFF);
    /// Conservative default: latch is a few TCXO ticks at 24MHz
    /// (HAL_TCXO_TICKS_PER_SECOND 24_000_000, tcxo_porting.h:21). 10_000 spins
    /// is ~us-scale and >> the handshake; sized to be re-tuned once measured.
    pub const DEFAULT: RefreshTimeout = RefreshTimeout(10_000);
    pub const fn iters(n: u32) -> Option<Self> {
        if n == 0 { None } else { Some(RefreshTimeout(n)) } // 0 => never polls
    }
    pub const fn get(self) -> u32 { self.0 }
}
fn refresh_with(&self, budget: RefreshTimeout) -> Result<(), ()> {
    // ... set refresh ...
    for _ in 0..budget.get() {
        if self.regs().tcxo_status().read().bits() & TCXO_VALID_BIT != 0 {
            return Ok(());
        }
        core::hint::spin_loop();
    }
    Err(())
}
// read_counter() uses RefreshTimeout::DEFAULT; a read_counter_timeout(budget)
// variant lets a caller opt into VENDOR_MAX. Fix the doc comment: TCXO = 24MHz,
// NOT 32kHz (tcxo.rs:75 is wrong by ~750x).

// The fix depends on UNMEASURED hardware behavior (does tcxo_status.valid
// auto-clear on a new refresh, or is it sticky?), so types cannot yet encode the
// correct handshake. Guard defensively AND document the open question; tighten to
// a hard guarantee once the HIL measurement lands.
fn refresh_with(&self, budget: RefreshTimeout) -> Result<(), ()> {
    // GUARD: do not trust a possibly-sticky valid flag from a prior refresh.
    // If valid is already set, this read could otherwise return Ok on iter 0 and
    // hand back the PREVIOUS latch. We cannot clear `valid` directly (no W bit
    // documented), so we record the pre-state and require we OBSERVE the request
    // being honored. NEEDS ON-BOARD CONFIRMATION (note (b)) of valid semantics.
    let _pre_valid = self.regs().tcxo_status().read().bits() & TCXO_VALID_BIT;
    let s = self.regs().tcxo_status().read().bits();
    unsafe { self.regs().tcxo_status().write(|w| w.bits(s | TCXO_REFRESH_BIT)); }
    for _ in 0..budget.get() {
        if self.regs().tcxo_status().read().bits() & TCXO_VALID_BIT != 0 {
            return Ok(());
        }
        core::hint::spin_loop();
    }
    Err(())
}
// DOC on read_counter(): "If tcxo_status.valid is sticky on this silicon, two
// rapid reads may return the same latch; this is being characterized on-board
// (defect 5). Once confirmed, refresh() will clear/re-arm valid before polling."
// If HIL shows valid IS sticky and auto-clears on refresh write: replace the
// guard with an explicit wait-for-valid-low then wait-for-valid-high edge.

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
#[non_exhaustive] // room to add Thirtytwo once a frame-width-aware data path + HIL exist
pub enum DataBits {
    /// 8-bit frames. The ONLY width the byte-oriented FIFO data path can run
    /// correctly, and one of only two the vendor HAL accepts.
    Eight,
}

impl DataBits {
    /// Accept only vendor- AND data-path-supported widths. Returns `None` for
    /// every other u8 (1..=7, 9..=31, 32, and the field-overflowing 33..=255),
    /// so a frame size that would truncate/spill into CTRA.trsm is unrepresentable.
    pub const fn from_u8(bits: u8) -> Option<Self> {
        match bits {
            8 => Some(DataBits::Eight),
            _ => None,
        }
    }
    /// Raw frame width in bits (always a supported value).
    pub const fn bits(self) -> u8 {
        match self { DataBits::Eight => 8 }
    }
    /// The 5-bit CTRA.dfs32 register value: `width - 1` (DFS encodes 0=4bit..31=35bit).
    /// Guaranteed in 0..=31, so it can never reach bit18/trsm.
    pub const fn dfs32(self) -> u32 { (self.bits() as u32) - 1 }
}

// Config field becomes:  pub data_bits: DataBits,   (Default::default() -> DataBits::Eight)
// configure_spi writes:  ctra |= config.data_bits.dfs32() << 13;  // <= 31, no spill

// Same `DataBits` enum as above resolves defect B in the same construct: by
// exposing ONLY `Eight`, structurally-valid-but-unrunnable widths (9..=31 program
// a legal DFS bit pattern yet mis-transmit through the byte FIFO; 16/24 are vendor
// "Not supported now"; 32 needs a data path that does not exist) cannot be built.
//
// FUTURE (gated on silicon + a 32-bit-aware data path, NOT shipped now):
//   pub enum DataBits { Eight, /* Thirtytwo */ }
//   8  => Some(Eight),
//   32 => Some(Thirtytwo),   // ONLY after transfer/write loops pack 4 bytes per
//                            //   FIFO slot AND a HIL test confirms a 32-bit frame
//   _  => None,              // 16/24 stay rejected (vendor: Not supported now)
// dfs32() for Thirtytwo would be 31 (==_32 0x1F), still inside the 5-bit field.

/// A validated SPI bus frequency: one whose SCKDV divisor lands in the
/// hardware-legal [2, 0xFFFE] (even) range for the current SPI_CLOCK_HZ, instead
/// of being silently clamped. Mirrors PWM's PwmPeriod::try_from_hz.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct Frequency { sckdv: u16 }

impl Frequency {
    /// SSI_CLK feeding the SCKDV divider (chip-specific).
    const SRC: u32 = crate::soc::chip::SPI_CLOCK_HZ;
    /// Derive from a target Hz. `None` when the required divisor would fall
    /// outside [2, 0xFFFE] — i.e. freq too high (>= SRC/2, divisor would be < 2)
    /// or too low (divisor > 0xFFFE) — rather than silently clamping to the rail.
    pub const fn from_hz(hz: u32) -> Option<Self> {
        if hz == 0 { return None; }
        let div = Self::SRC / hz;            // SCK = SRC / SCKDV, no /2, no -1 (matches sckdv())
        if div < 2 || div > 0xFFFE { return None; }
        Some(Frequency { sckdv: (div as u16) & !1 }) // SCKDV bit0 read-only 0 -> force even
    }
    /// The 16-bit SCKDV value (even, in [2, 0xFFFE]).
    pub const fn sckdv(self) -> u16 { self.sckdv }
}

// Config:  pub frequency: Frequency,   Default = Frequency::from_hz(1_000_000).unwrap()
// configure_spi:  r.spi_brs().write(|w| unsafe { w.bits(config.frequency.sckdv() as u32) });
// The free `sckdv(pclk,freq)` fn + its unit/proptests stay for internal use/back-compat.

// configure_spi_source_clock() is #[cfg(feature = "chip-ws63")] only; on BS2X the
// constructor currently programs SCKDV against an unconfirmed soc::bs21::SPI_CLOCK_HZ
// (=32_000_000, TODO 'assumed') and opens NO clock gate. A type cannot express
// 'the BS2X clock tree is brought up', so guard at the cfg boundary: refuse to
// silently emit a dead/wrong-clock config until the fbb_bs2x port + silicon exist.
#[cfg(all(feature = "chip-bs2x", not(feature = "unproven-bs2x-spi")))]
compile_error!(
    "BS2X SPI clocking is not brought up on silicon: configure_spi_source_clock \
     (CRG divider + TCXO->PLL switch + CKEN gate) has no BS2X analogue and \
     SPI_CLOCK_HZ=32MHz is an unconfirmed TODO. Opt in with feature \
     `unproven-bs2x-spi` once fbb_bs2x spi_porting.c is ported and a HIL run \
     confirms the source clock + gate."
);
// When the BS2X port lands, replace the guard with a real
// #[cfg(feature = "chip-bs2x")] configure_spi_source_clock() body (self-enable the
// gate, same 'construct -> clocked' contract WS63 already honors) and drop the
// compile_error.

// PLL-locked is a clock_init/board fact, not expressible as a Config type, so keep
// it doc-and-guard but make the precondition load-bearing rather than prose-only:
#[cfg(feature = "chip-ws63")]
fn configure_spi_source_clock() {
    // SAFETY/PRECONDITION: the 480 MHz FNPLL must be locked (app clock_init runs
    // before driver init). If it is not, switching CLK_SEL bit6 to PLL yields no
    // SSI_CLK and every transfer hits SpiError::Timeout (the bounded wait_until at
    // spi.rs:64 already converts that hang into a returned error -> caller-visible).
    debug_assert!(
        crate::clock_init::pll_locked(), // add a cheap CRG lock-status read helper
        "SPI source switch to PLL before FNPLL lock; run clock_init first"
    );
    let ssi_mhz = (crate::soc::chip::SPI_CLOCK_HZ / 1_000_000).max(1);
    // div clamp [1,0x1F] is the 5-bit CRG field (SPI_DIV_LEN=5). With the shipped
    // 160MHz SPI_CLOCK_HZ, div=3 and the clamp is inert; if SPI_CLOCK_HZ were set
    // below 480/31~=15.5MHz the clamp WOULD alias -> a const-assert pins that:
    const _: () = assert!(
        SPI_PLL_ROOT_MHZ / (crate::soc::chip::SPI_CLOCK_HZ / 1_000_000) <= 0x1F,
        "SPI_CLOCK_HZ too low: CRG source divider would saturate at 0x1F and alias SSI_CLK"
    );
    let div = (SPI_PLL_ROOT_MHZ / ssi_mhz).clamp(1, 0x1F);
    /* ... existing CRG/CLK_SEL/CKEN sequence unchanged ... */
}

// The 32 kHz source is a BOARD-POPULATION fact (a soldered crystal). No type and
// no CKEN bit can express it (RTC is AON; absent from clock.rs Peripheral enum;
// rtc_porting.c has no clock-enable). So construction becomes fallible via a
// runtime liveness probe, plus an explicit unsafe escape hatch for BSPs that
// already know the crystal is provisioned.

impl<'d> RtcDriver<'d> {
    /// Construct only if the 32.768 kHz source is live. Probes the free-running
    /// counter: reads `current_value()` twice across a bounded settle window and
    /// returns `Some` iff it advanced. Returns `None` on an EVB whose 32 kHz
    /// crystal is unpopulated (counter stuck).
    ///
    /// # Warning (doc-and-guard)
    /// On a board with NO 32 kHz crystal, per bring-up notes any RTC register
    /// access can stall the bus. This probe touches the block, so it can itself
    /// hang; only call it where a watchdog/timeout backstop exists, or prefer
    /// [`new_assume_clocked`] when the BSP already vouches for the crystal.
    pub fn new(rtc: Rtc<'d>) -> Option<Self> {
        let drv = Self { _rtc: rtc };
        let a = drv.regs().rtc_current_value().read().bits();
        // bounded settle: a few 32 kHz ticks ≈ tens of µs; spin a fixed count.
        for _ in 0..RTC_PROBE_SETTLE_ITERS { core::hint::spin_loop(); }
        let b = drv.regs().rtc_current_value().read().bits();
        if a != b { Some(drv) } else { None }
    }

    /// Construct without probing. The caller asserts the 32.768 kHz crystal is
    /// populated and the AON RTC is clocked; otherwise register access may stall
    /// the bus.
    ///
    /// # Safety
    /// Only the BSP, which knows the board's crystal population, may call this.
    pub unsafe fn new_assume_clocked(rtc: Rtc<'d>) -> Self {
        Self { _rtc: rtc }
    }
}

/// Settle iterations for the construction liveness probe (≈ a few 32 kHz ticks).
const RTC_PROBE_SETTLE_ITERS: u32 = 4_000;

// The vendor v100 only ever programs RTC_MODE_FREE_RUN (0): hal_rtc_v100_config_load
// unconditionally forces mode=FREE_RUN on every load. mode=1 (USER_DEF) is an
// undocumented/unexercised silicon mode with no attested counting/interrupt
// behavior. Remove it from the first-class API rather than presenting it as an
// equal option. Two equivalent ways:
//
// (A) Collapse the enum to the only attested mode (keeps configure's shape):
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
#[non_exhaustive]
pub enum RtcMode {
    /// Free-running counter (RTC_MODE_FREE_RUN = 0) — the only vendor-attested mode.
    FreeRunning,
}
// control_bits then never sets bit1:
const fn control_bits(_mode: RtcMode) -> u32 { CTRL_ENABLE | CTRL_INT_MASK }
//
// (B) Preferred minimal: drop the `mode` parameter entirely, hardwire FreeRun:
impl<'d> RtcDriver<'d> {
    pub fn configure(&mut self, reload: RtcReload) {
        self.set_load(reload);              // stop/write/restart (see set_load)
        let ctrl = CTRL_ENABLE | CTRL_INT_MASK; // mode bit1 always 0 = FREE_RUN
        unsafe { self.regs().rtc_control().write(|w| w.bits(ctrl)); }
    }
}
// If mode=1 is later attested on silicon, re-add a UserDefined variant behind
// #[non_exhaustive] without a further break.

// Mirror PwmPeriod: a validated non-zero reload count, so a 0 reload (degenerate
// immediate-expiry counter the vendor rejects with ERRCODE_INVALID_PARAM) is
// UNREPRESENTABLE rather than silently programmed. RTC_LOAD_COUNT is a genuine
// full-width 32-bit reg (PAC Ux=u32), so the inner type is u32 (no truncation).
#[derive(Clone, Copy, Debug, PartialEq, Eq, PartialOrd, Ord)]
pub struct RtcReload(u32);

impl RtcReload {
    /// Wrap a raw reload count in 32.768 kHz ticks. `None` for 0.
    pub const fn from_count(count: u32) -> Option<Self> {
        if count == 0 { None } else { Some(RtcReload(count)) }
    }

    /// Derive the reload from a millisecond interval. `None` when the interval is
    /// 0 or rounds to a 0 count (sub-tick), or overflows u32.
    pub const fn try_from_ms(ms: u32) -> Option<Self> {
        // count = ms * 32768 / 1000
        let count = (ms as u64 * RTC_CLOCK_HZ as u64) / 1000;
        if count == 0 || count > u32::MAX as u64 { return None; }
        Some(RtcReload(count as u32))
    }

    /// The raw reload count (always >= 1).
    pub const fn count(self) -> u32 { self.0 }
}
// configure(reload: RtcReload) and set_load(reload: RtcReload) take it by value;
// .count() is what is written to RTC_LOAD_COUNT.

// Every vendor reload path brackets the write with stop/start (hal_rtc_stop;
// write load_count; hal_rtc_start). Writing RTC_LOAD_COUNT on a live free-running
// counter is exactly what the vendor avoids (glitched/late-latched first
// interval). The precondition (disable before write) is invisible at the API, so
// ENFORCE it inside set_load via read-modify-write of the enable bit rather than
// documenting it. This is not a type change — the safe ordering is the only thing
// the method does.
impl<'d> RtcDriver<'d> {
    /// Set the reload (alarm) value, bracketing the write with the vendor
    /// stop -> write load_count -> restart sequence so a live-counter reload
    /// cannot latch a glitched first interval.
    pub fn set_load(&mut self, reload: RtcReload) {
        let ctrl = self.regs().rtc_control().read().bits();
        let was_enabled = ctrl & CTRL_ENABLE != 0;
        if was_enabled {
            // stop: clear enable bit0 (hal_rtc_stop)
            unsafe { self.regs().rtc_control().write(|w| w.bits(ctrl & !CTRL_ENABLE)); }
        }
        unsafe { self.regs().rtc_load_count().write(|w| w.bits(reload.count())); }
        if was_enabled {
            // restart: restore the original control word (hal_rtc_start)
            unsafe { self.regs().rtc_control().write(|w| w.bits(ctrl)); }
        }
    }
}

// NOT a type/API change. RTC_LOAD_COUNT and RTC_CURRENT_VALUE are genuine 32-bit
// registers (PAC Ux=u32, single reg; vendor volatile uint32_t at regs_def.h:58-59)
// and the public API already types them as u32 — the API WIDTH IS CORRECT. The
// '48-bit' claim in the rtc.rs module doc and RTC_COUNTER_WIDTH=48 is the fiction.
// Fix the comment/const to reflect the 32-bit register reality (and note that the
// silicon-exposed width must be measured on a clocked board), e.g.:
//
//   /// RTC register width in bits. RTC_LOAD_COUNT / RTC_CURRENT_VALUE are 32-bit
//   /// registers (PAC Ux=u32); any wider internal counter is not software-visible.
//   /// On-silicon width unconfirmed (EVB crystal unpopulated).
//   pub const RTC_COUNTER_WIDTH: usize = 32;
//
// Per PWM's lesson (the type must encode MEASURED hardware, not the datasheet),
// flag that the true silicon-exposed counter width needs on-board confirmation
// before either 32 or 48 is asserted as fact.

/// A validated watchdog timeout: a millisecond value guaranteed to fit the
/// 24-bit WDT_LOAD field at the current chip's WDT_CLOCK_HZ. Once constructed,
/// programming it is exact -- never clamped, never wrapped.
#[derive(Clone, Copy, Debug, PartialEq, Eq, PartialOrd, Ord)]
pub struct WdtTimeout {
    /// The 24-bit WDT_LOAD field value (already shifted right by WDT_LOAD_RESEV).
    load: u32,
}

impl WdtTimeout {
    /// Largest representable timeout in ms at WDT_CLOCK_HZ:
    /// (WDT_MAX_LOAD<<RESEV)*1000/clk = 178_956 @24MHz, 134_217 @32MHz.
    pub const MAX_MS: u32 =
        (((WDT_MAX_LOAD as u64) << WDT_LOAD_RESEV) * 1000 / WDT_CLOCK_HZ as u64) as u32;

    /// Build from milliseconds. `None` if `ms == 0` (instant-reset / dead WDT,
    /// which the vendor rejects with ERRCODE_INVALID_PARAM) or if the resulting
    /// load would exceed the 24-bit field (would otherwise be silently clamped).
    pub const fn from_ms(ms: u32) -> Option<Self> {
        if ms == 0 {
            return None;
        }
        let cycles = (ms as u64) * (WDT_CLOCK_HZ as u64) / 1000;
        let load = cycles >> WDT_LOAD_RESEV;
        if load == 0 || load > WDT_MAX_LOAD as u64 {
            return None; // load==0 guards the TOP_MIN floor; >max guards the clamp
        }
        Some(WdtTimeout { load: load as u32 })
    }

    /// The 24-bit WDT_LOAD field (always 1..=WDT_MAX_LOAD).
    pub const fn load_field(self) -> u32 { self.load }
}

// configure becomes total -- no clamp, no zero-load path:
pub fn configure(&mut self, timeout: WdtTimeout, mode: WdtMode,
                 reset_enable: bool, reset_pulse: ResetPulseLength) {
    self.unlock();
    let load = timeout.load_field();
    unsafe { self.regs().wdt_load().write(|w| w.bits(load << WDT_LOAD_RESEV)); }
    /* ...cr bits unchanged... */
}

// Folded into WdtTimeout::from_ms above -- the `if ms == 0 { return None; }`
// branch (and the redundant `load == 0` guard) make a zero/sub-minimum reload
// UNREPRESENTABLE. There is no WdtTimeout value with load == 0, so configure
// can never program an instant-reset watchdog.
//
// Test churn: delete `zero_timeout_yields_zero_load` (it asserted the BUG) and
// replace with rejection tests:
#[test] fn from_ms_rejects_zero() { assert!(WdtTimeout::from_ms(0).is_none()); }
#[test] fn from_ms_smallest_is_one_ms() {
    let t = WdtTimeout::from_ms(1).unwrap();
    assert!(t.load_field() >= 1); // 24000/32000 cycles >> 8 = ~93/125
}
#[test] fn from_ms_rejects_above_max() {
    assert!(WdtTimeout::from_ms(WdtTimeout::MAX_MS).is_some());
    assert!(WdtTimeout::from_ms(WdtTimeout::MAX_MS + 1).is_none());
}

/// Bring up the WDT clock the way the vendor expects. Unlike PWM (whose
/// `pwm_port_clock_enable` is load-bearing), the WS63 WDT lives in the
/// always-on (AON) domain whose `wdt_gate` is RESET-DEFAULT-ON and whose
/// vendor `watchdog_turnon_clk()` porting hook is an empty no-op -- so on the
/// normal boot path there is nothing to enable. This guard exists only to make
/// the precondition explicit and to recover a WDT that a caller deliberately
/// gated (low-power experiments). It is idempotent.
fn enable_wdt_clock() {
    #[cfg(feature = "chip-ws63")]
    {
        const AON_CRG_CKEN_CTL: usize = 0x4400_???? /* AON CRG base + CKEN_CTL */;
        const AON_SOFT_RST_CTL: usize = 0x4400_???? /* + SOFT_RST_CTL */;
        const WDT_GATE: u32 = 1 << 4;       // AON_CRG_CKEN_CTL[4]
        const WDT_SOFT_RST: u32 = 1 << 1;   // AON_SOFT_RST_CTL[1]
        // SAFETY: fixed AON-CRG MMIO; RMW of clock/reset bits is benign + idempotent.
        unsafe fn rmw(addr: usize, clear: u32, set: u32) {
            let p = addr as *mut u32;
            let v = (core::ptr::read_volatile(p) & !clear) | set;
            core::ptr::write_volatile(p, v);
        }
        unsafe {
            rmw(AON_SOFT_RST_CTL, WDT_SOFT_RST, 0); // deassert reset (0 = released)
            rmw(AON_CRG_CKEN_CTL, 0, WDT_GATE);     // enable gate
        }
    }
}
// Called once at the top of configure():
