/// A baud rate validated against the ACTUAL UART base clock at construction.
/// Once a `BaudRate` exists, `1 <= pclk/(16*baud) <= 65535`, so the 16-bit
/// integer divider DIV_H:DIV_L is guaranteed non-zero and non-overflowing —
/// a div=0 dead line (or a >0xFFFF overflow) is unrepresentable.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct BaudRate {
    baud: u32,
    pclk: u32,
}

impl BaudRate {
    /// Build a baud rate for a specific base clock `pclk` (Hz). Returns `None`
    /// unless the integer divider `div = pclk/(16*baud)` is in `1..=65535`.
    pub const fn try_new(baud: u32, pclk: u32) -> Option<Self> {
        if baud == 0 { return None; }
        // div64 = pclk*4/baud (= div*64); div = div64 >> 6.
        let div64 = (pclk as u64 * 4) / baud as u64;
        let div = div64 >> 6;            // the value written to DIV_H:DIV_L
        if div == 0 || div > 0xFFFF { return None; }   // HIGH-end and LOW-end guard in one
        Some(BaudRate { baud, pclk })
    }
    /// Convenience for a known clock source enum (see UartClock).
    pub const fn for_clock(baud: u32, clk: UartClock) -> Option<Self> {
        Self::try_new(baud, clk.hz())
    }
    pub const fn baud(self) -> u32 { self.baud }
    pub const fn pclk(self) -> u32 { self.pclk }
    /// The exact (div_l, div_h, div_fra) bytes configure_uart will program.
    pub const fn divider_regs(self) -> (u8, u8, u8) {
        let div64 = (self.pclk as u64 * 4) / self.baud as u64;
        let div = (div64 >> 6) as u32;
        (((div & 0xFF) as u8), (((div >> 8) & 0xFF) as u8), ((div64 & 0x3F) as u8))
    }
}
// Config.baudrate: u32  ->  Config.baud: BaudRate   (and Config no longer holds a bare clock_hz; see next row)

/// The UART baud-base clock, named so the caller cannot silently mismatch it.
/// Replaces the foot-gun `Option<u32>` (None == "hope clock_init ran").
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum UartClock {
    /// Post-`clock_init` PLL base (UART_CLOCK_HZ = 160 MHz on WS63).
    Pll,
    /// flashboot console base on a 24 MHz-TCXO board (pre-clock_init).
    BootTcxo24M,
    /// flashboot console base on a 40 MHz-TCXO board (pre-clock_init).
    BootTcxo40M,
    /// Read the live HW_CTL strap to pick 24/40 MHz at runtime (uart_boot_clock_hz()).
    BootProbe,
    /// Escape hatch for an externally-known base (still feeds BaudRate validation).
    Hz(u32),
}
impl UartClock {
    pub fn hz(self) -> u32 {
        match self {
            UartClock::Pll => crate::soc::chip::UART_CLOCK_HZ,
            UartClock::BootTcxo24M => crate::soc::chip::UART_BOOT_CLOCK_24M_HZ,
            UartClock::BootTcxo40M => crate::soc::chip::UART_BOOT_CLOCK_40M_HZ,
            UartClock::BootProbe => crate::soc::chip::uart_boot_clock_hz(),
            UartClock::Hz(h) => h,
        }
    }
}
// The base now lives inside the validated BaudRate (BaudRate::for_clock(baud, clk)).
// Config drops `clock_hz` entirely: `pub baud: BaudRate` already carries the pclk it
// was validated against, so the base used for the divider and the base used for the
// guard can never diverge.

// DRIVER-LEVEL self-enable, mirroring PWM's enable_pwm_clock ("construct -> clocked").
// Called at the top of configure_uart, BEFORE any divider/frame write.
fn enable_uart_clock(idx: u8) {
    #[cfg(feature = "chip-ws63")]
    {
        // CKEN_CTL1 holds the UART gates (clock.rs: Uart0/1/2 -> bits 18/19/20).
        const CLDO_CRG_CKEN_CTL1: usize = 0x4400_1104; // CKEN_CTL0 is 0x..1100 (see pwm.rs)
        let bit = 18 + idx as u32; // 18=UART0, 19=UART1, 20=UART2
        // SAFETY: fixed CLDO_CRG MMIO; setting one clock-enable bit is benign RMW.
        unsafe {
            let p = CLDO_CRG_CKEN_CTL1 as *mut u32;
            core::ptr::write_volatile(p, core::ptr::read_volatile(p) | (1 << bit));
        }
        // Pinmux: UART{idx}_TXD_SEL / RXD_SEL to the UART function (vendor
        // uart_port_config_pinmux). The exact IOMUX register + field per board pad
        // is the part types genuinely cannot express -> doc-and-guard, confirm on board.
        enable_uart_pinmux(idx);
    }
}
