// The combo stays representable (both are legal independently); configure_uart is
// fixed to HONOR the v151 hardware meaning instead of writing a frame it cannot
// produce. Document on StopBits::Two and guard the write:
//
//   /// 2 stop bits — EXCEPT with DataBits::Five, where the v151 core (stp=1,
//   /// dlen=0) produces 1.5 stop bits. configure_uart reports/normalizes this.
//   Two,
//
// In configure_uart, replace the unconditional bit-7 set (uart.rs:155-157):
   match (config.data_bits, config.stop_bits) {
       (DataBits::Five, StopBits::Two) => {
           // v151: stp=1 + dlen=0 == 1.5 stop bits. Set bit7 and let the caller
           // know the realized frame is 5-data/1.5-stop (the only thing HW can do).
           ctl |= 1 << 7; // == 1.5 stop bits here, documented, not silently "2"
       }
       (_, StopBits::Two) => { ctl |= 1 << 7; } // genuine 2 stop bits
       (_, StopBits::One) => {}
   }
// (Alternative if a stronger guarantee is wanted: add StopBits::OneAndHalf and a
//  fallible Frame::new(data,parity,stop) that returns None for the contradictory
//  Five+Two request. Kept as doc-and-guard here because both enum values are
