/// Bounded conversion-done wait, mirroring vendor `COUNT_THRESHOLD 1000`.
const DONE_POLL_THRESHOLD: u32 = 1000;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
#[non_exhaustive]
pub enum GadcError {
    /// Done flag (rpt_gadc_data_3 bit0) never asserted within DONE_POLL_THRESHOLD
    /// polls — AFE not live, no conversion clock, or un-provisioned input.
    ConversionTimeout,
    /// Power-up acknowledge bit never asserted (see try_new).
    PowerUpTimeout,
}

fn convert_once(&self) -> Result<i32, GadcError> {
    let r = self.regs();
    unsafe {
        delay_us(5);
        pmu_rmw(PMU_AFE_GADC_CFG, 0, S2D_GADC_MUX_EN);
        pmu_rmw(PMU_AFE_GADC_CFG, S2D_GADC_ISO_EN, 0);
        delay_us(5);
        pmu_rmw(PMU_AFE_GADC_CFG, 0, S2D_GADC_EN);
        // BOUNDED done-wait (was an unbounded `while ... { spin_loop() }`).
        let mut cnt = 0u32;
        while r.rpt_gadc_data_3().read().bits() & 0x1 == 0 {
            if cnt >= DONE_POLL_THRESHOLD {
                // re-isolate so a timed-out attempt leaves the AFE parked.
                pmu_rmw(PMU_AFE_GADC_CFG, S2D_GADC_EN, 0);
                pmu_rmw(PMU_AFE_GADC_CFG, S2D_GADC_MUX_EN, S2D_GADC_ISO_EN);
                return Err(GadcError::ConversionTimeout);
            }
            cnt += 1;
            core::hint::spin_loop();
        }
        pmu_rmw(PMU_AFE_GADC_CFG, S2D_GADC_EN, 0);
        delay_us(5);
        pmu_rmw(PMU_AFE_GADC_CFG, S2D_GADC_MUX_EN, S2D_GADC_ISO_EN);
        let raw = r.rpt_gadc_data_2().read().bits();
        Ok(sign_extend18(raw))
    }
}

/// Fallible single conversion (the discarded-first-sample retry is also bounded).
pub fn try_read(&mut self, channel: AdcChannel) -> Result<i32, GadcError> {
    /* select channel as before */
    if self.first_sample { self.convert_once()?; self.first_sample = false; }
    self.convert_once()
}

const PWRUP_POLL_THRESHOLD: u32 = 1000;
const PWR_ACK_BIT: u32 = 1 << 2;   // PMU_AFE_DIG_PWR_EN[2] RO (gadc.rs:37)
const GADC_CFG_DONE_BIT: u32 = 1 << 4; // PMU_AFE_GADC_CFG[4] RO (gadc.rs:36)

/// Bounded poll of an RO ack bit in a PMU-AFE register. Iteration-bounded so a
/// stuck rail/handshake reports an error instead of (silently) over-delaying.
unsafe fn pmu_wait_ack(off: usize, mask: u32) -> Result<(), GadcError> {
    let mut cnt = 0u32;
    while unsafe { rd(PMU_AFE_BASE + off) } & mask == 0 {
        if cnt >= PWRUP_POLL_THRESHOLD { return Err(GadcError::PowerUpTimeout); }
        cnt += 1;
        core::hint::spin_loop();
    }
    Ok(())
}

/// Power up the GADC and confirm the AFE is actually live. Self-enables the
/// GADC clock tree (cfg_clken) and acks each documented RO bit; returns Err if
/// any acknowledge never lands. Construct -> guaranteed-live.
pub fn try_new(_gadc: GadcPeriph<'d>) -> Result<Self, GadcError> {
    let r = unsafe { &*GadcPeriph::ptr() };
    unsafe {
        wr(AON_AFE_ISO, rd(AON_AFE_ISO) | (1 << 10));
        pmu_wr(PMU_AFE_ISO_CFG, 0);
        delay_us(30);
        pmu_wr(PMU_AFE_DIG_PWR_EN, 0x3);
        pmu_wait_ack(PMU_AFE_DIG_PWR_EN, PWR_ACK_BIT)?; // was: delay_us(50)
        pmu_rmw(PMU_AFE_DIG_PWR_EN, 1 << 1, 0);
        pmu_wr(PMU_AFE_ADC_RST_N, 1);
        pmu_wr(PMU_AFE_CLK_EN, 1);
        pmu_wr(PMU_AFE_SOFT_RST, 1);
        r.cfg_clken().write(|w| w.bits(0));
        r.cfg_rstn().write(|w| w.bits(0));
        r.cfg_clken().write(|w| w.bits(0x0011_1111)); // self-enable GADC clock gates
        /* Phase B LDO bring-up unchanged */
        r.cfg_clk_div_0().write(|w| w.bits(GadcClkDiv::COMMON_DEFAULT.bits()));
        /* Phase C analog enable unchanged up to hal_gafe_enable */
        pmu_wr(PMU_AFE_GADC_CFG, S2D_GADC_ISO_EN | S2D_GADC_MUX_EN);
        pmu_wait_ack(PMU_AFE_GADC_CFG, GADC_CFG_DONE_BIT)?; // was: delay_us(30)
        pmu_rmw(PMU_AFE_GADC_CFG, S2D_GADC_ISO_EN, 0);
        pmu_rmw(PMU_AFE_GADC_CFG, 0, S2D_GADC_EN);
    }
    Ok(Self { _gadc: PhantomData, first_sample: true })
}

/// Replace the 64 MHz CPU-cycle spin with the clock-independent TCXO delay the
/// vendor uses (uapi_tcxo_delay_us). The TCXO runs at a fixed rate regardless of
/// the app-core PLL/XO setting, so settling times are correct on any boot clock.
#[inline]
fn delay_us(us: u32) {
    // crate::tcxo provides a calibrated us delay (see tcxo.rs); fall back to the
    // cycle spin only if the tcxo block is unavailable at this call site.
    crate::tcxo::delay_us(us);
}
// If a tcxo handle is genuinely unreachable here, keep the spin but DOCUMENT the
// hard 64 MHz precondition at the type boundary and guard with a debug_assert in
// tests; the frequency cannot be expressed as a value-newtype on a free fn.

/// Validated GADC common clock divider for cfg_clk_div_0. Two 12-bit fields:
/// ana_div_th[11:0] and prechg_div_th[23:12] (PAC widths confirmed: both 12-bit).
/// A zero prechg divider produces no usable conversion clock (feeds the bounded
/// done-poll), so the constructor rejects prechg_div == 0.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct GadcClkDiv(u32);

impl GadcClkDiv {
    /// UNVERIFIED vendor default placeholder (was raw 0x27 = ana_div 0x27,
    /// prechg_div 0). Marked needs-board-confirmation: COMMON_DEFAULT not in this
    /// checkout. Provided as a *validated* value, not a bare magic literal.
    pub const COMMON_DEFAULT: GadcClkDiv = GadcClkDiv(0x27);

    /// Build from the two 12-bit dividers. Returns None if either exceeds 12 bits
    /// (would truncate into the other field) or if prechg_div == 0 (no precharge
    /// clock -> conversion never finishes).
    pub const fn new(ana_div: u16, prechg_div: u16) -> Option<Self> {
        if ana_div > 0x0FFF || prechg_div > 0x0FFF || prechg_div == 0 {
            return None;
        }
        Some(GadcClkDiv((ana_div as u32) | ((prechg_div as u32) << 12)))
    }
    pub const fn bits(self) -> u32 { self.0 }
}

/// The accumulated/averaged GADC sample. The 18-bit-signed (sign bit 17)
/// interpretation is the ACCUMULATED_AVERAGE_OUTPUT width selected by cfg_tst_1=2
/// (gadc.rs:149) — NOT the raw 13-bit conversion. The accumulation count for
/// BS2X v153 (vendor `satrt_cnt`) is UNCONFIRMED in this checkout; if it differs
/// from v154's 0x18 the magnitude scales and the sign-bit position may move.
/// Returned as the existing i32 from sign_extend18; documented as 'raw signed
/// accumulator units, scale TBD on board', not converted to volts.
#[inline]
fn sign_extend18(raw: u32) -> i32 { /* unchanged, exhaustively host-tested */
    let v = raw & 0x3FFFF;
    if v & (1 << 17) != 0 { (v as i32) - 0x4_0000 } else { v as i32 }
}
// FLAG (PWM-high-half class): if on BS2X silicon bits[17:13] turn out to carry
// status/overflow (not magnitude) or the sign bit is not bit 17, sign_extend18's
// mask 0x3FFFF and `1<<17` must be re-derived from measurement before any
// voltage conversion is added. Do NOT bake a volts() conversion until the
// satrt_cnt-dependent scale is measured.

// Module is ALREADY chip-gated at the use site (lib.rs:101):
//   #[cfg(feature = "chip-bs21")] pub mod gadc;
// Add an in-FILE belt-and-suspenders guard so the raw BS2X addresses can never
// compile for WS63 even if the module is pulled in directly:
#![cfg(feature = "chip-bs21")]
compile_error_if_not_bs2x!(); // or:
#[cfg(not(feature = "chip-bs21"))]
compile_error!("gadc is BS2X-only; WS63 uses the lsadc (v154) block at 0x4400_C000");

// The off-PAC sub-block addresses stay raw consts but are documented as the
// BS2X memory map and now unreachable on WS63 by the cfg gate (so they cannot
