// REMOVE `impl Default for I2sConfig` for the Master case entirely — it is the
// canonical broken config (Master + zero dividers). Provide Default only for the
// safe role, or no Default at all and force the explicit constructors:
impl Default for I2sConfig<Slave> { fn default() -> Self { I2sConfig::slave() } }
// (No Default for I2sConfig<Master>: a master MUST name its dividers.)

// FIRST regenerate ws63-pac i2s_crg from vendor regs_def (bclk_div_en@b0,
// crg_clken@b1, bclk_sel@b2, fs_sel@b4) — the SVD currently fabricates clk_en@b8.
// THEN drive the vendor enable SEQUENCE in configure() (no user-facing type needed;
// this is a driver-internal correctness fix, modeled as the 'result' of construct->clocked):
const CRG_BCLK_DIV_EN: u32 = 1 << 0;
const CRG_CLKEN:       u32 = 1 << 1;
const CRG_BCLK_SEL:    u32 = 1 << 2; // written 0 by vendor
const CRG_FS_SEL:      u32 = 1 << 4; // written 0 by vendor
if cfg.role.is_master() {
    // vendor order: div_en=0, write divider, div_en=1, then crg_clken=1
    r.i2s_crg().modify(|_,w| w.bits(0));                 // bclk_div_en=0, sels=0
    r.i2s_bclk_div_num().write(|w| w.bits(bclk as u32)); // divider already validated
    r.i2s_crg().modify(|r0,w| w.bits(r0.bits() | CRG_BCLK_DIV_EN));
    r.i2s_crg().modify(|r0,w| w.bits(r0.bits() | CRG_CLKEN));
}

// Regenerate ws63-pac `mode` from vendor regs_def, then re-pack in configure() to the
// REAL silicon layout: mode(i2s/pcm)@b0, pcm_mode@b1, rxws_select@b2, ext_rec_en@b3,
// chn_num@b4:5, clk_edge@b6, ms_mode_sel(master/slave)@b7.
let mut mode: u32 = 0;
if matches!(cfg.mode, I2sMode::Pcm) { mode |= 1 << 0; }   // i2s/pcm select (was bit4)
mode |= (cfg.channels as u32 & 0x3) << 4;                  // chn_num bits[4:5] (was bits[0:1])
if matches!(cfg.clock_edge, ClockEdge::Falling) { mode |= 1 << 6; } // (was bit2)
if cfg.role.is_master() { mode |= 1 << 7; }                // ms_mode_sel (was bit3!)
// bits 1(pcm_mode),2(rxws_select),3(ext_rec_en) left 0 unless those features added.
r.mode().write(|w| w.bits(mode));

// Re-table to the silicon chn_num codes: 00=2ch,01=4ch,10=8ch,11=16ch — there is NO 6ch.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ChannelCount {
    Two = 0,      // 2ch (stereo)
    Four = 1,     // 4ch
    Eight = 2,    // 8ch  (was wrongly coded as Six)
    Sixteen = 3,  // 16ch (was wrongly coded as Eight)
}
