// Re-table to the silicon 3-bit data_width_set enum: RESERVED=0, 16-bit=1, 18-bit=2,
// 20-bit=3, 24-bit=4, 32-bit=5. The 8/10/12/14-bit widths do NOT exist in this IP, and
// code0 is reserved (no valid width) so it must not be the Default.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum DataWidth {
    Bits16 = 1,
    Bits18 = 2,
    Bits20 = 3,
    Bits24 = 4,
    Bits32 = 5, // NEEDS ON-BOARD CONFIRMATION it actually latches (see summary open-Q a)
}
