// Mirror PWM's enable_pwm_clock(): configure() self-enables the SIO/I2S clock tree the
// way vendor sio_porting_clock_enable() does, so 'construct -> clocked'. Gated to chip-ws63.
fn enable_i2s_clock() {
    #[cfg(feature = "chip-ws63")]
    {
        const CLDO_CRG_CKEN_CTL0: usize = 0x4400_1100; // I2S_CLKEN bit12, I2S_BUS_CLKEN bit11
        const CMU_NEW_CFG0:       usize = /* per sio_porting.c */ 0x4400_10XX; // bit0 = DIV_AD_RSTN_SYNC
        const I2S_BUS_CKEN: u32 = 1 << 11;
        const I2S_CLKEN:    u32 = 1 << 12;
        const CMU_DIV_AD_RSTN_SYNC: u32 = 1 << 0;
        unsafe {
            rmw(CMU_NEW_CFG0, 0, CMU_DIV_AD_RSTN_SYNC); // CMU sync first (vendor order)
            rmw(CLDO_CRG_CKEN_CTL0, 0, I2S_BUS_CKEN | I2S_CLKEN);
        }
    }
}
// called at the top of configure(), before any SIO MMIO write. Doc-and-guard because the
// exact CMU_NEW_CFG0 address + whether all three bits are mandatory needs on-board confirmation.

/// FIFO threshold, bounded to the physical SIO FIFO depth (vendor SIO_FIFO_SIZE=8).
/// A threshold above the depth can never be reached, so the threshold IRQ would never fire.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct FifoThreshold(u8);
impl FifoThreshold {
    pub const DEPTH: u8 = 8; // SIO_FIFO_SIZE — NEEDS on-board confirmation (summary open-Q c)
    pub const RX_DEFAULT: FifoThreshold = FifoThreshold(7); // vendor SIO_RX_THRESHOLD
    pub const TX_DEFAULT: FifoThreshold = FifoThreshold(4); // vendor SIO_TX_THRESHOLD
    pub const fn new(n: u8) -> Option<Self> {
        if n <= Self::DEPTH { Some(FifoThreshold(n)) } else { None }
    }
    pub const fn get(self) -> u8 { self.0 }
}

// Keep `loopback: bool` but fix the write to a read-modify-write of the loop bit and
// document that loopback also needs the dedicated txrx-enable + crg clock sequence
// (vendor hal_sio_v151_txrx_enable). version is mostly read-only (bits0:7=IP version),
// so a blind write is fragile.
const VERSION_LOOP: u32 = 1 << 8;
if cfg.loopback {
    r.version().modify(|r0, w| w.bits(r0.bits() | VERSION_LOOP)); // RMW, not blind write
    // NOTE/doc: a working loop additionally requires the txrx-enable sequence
    // (which toggles crg_clock_enable) under CONFIG_I2S_SUPPORT_LOOPBACK; calling
    // configure() with loopback=true is necessary but not sufficient on its own.
}

