// CLASS C — driver self-enables its own gate in new(), mirroring PWM's
// enable_pwm_clock() and gadc's pmu_rmw bring-up. A DIFFERENT peripheral
// (CLDO_CRG) the lsadc RegisterBlock cannot reach -> raw MMIO, gated to ws63.
#[cfg(feature = "chip-ws63")]
fn enable_lsadc_clock() {
    const CLDO_CRG_RST_SOFT_CFG_1: usize = 0x4400_1138;
    const SOFT_RST_LSADC_N: u32 = 1 << 5;
    const SOFT_RST_LSADC_BUS_N: u32 = 1 << 7;
    // SAFETY: fixed CLDO_CRG MMIO; deassert (set, active-low) both LSADC resets.
    unsafe {
        let p = CLDO_CRG_RST_SOFT_CFG_1 as *mut u32;
        let v = core::ptr::read_volatile(p) | SOFT_RST_LSADC_N | SOFT_RST_LSADC_BUS_N;
        core::ptr::write_volatile(p, v);
    }
}
pub fn new(lsadc: Lsadc<'d>) -> Self {
    enable_lsadc_clock();      // construct -> clocked, like PWM
    Self { _lsadc: lsadc }
}

// CLASS C — full AFE bring-up as ONE staged method; da_lsadc_rwreg_1..3 are
// NOT in the PAC RegisterBlock (confirmed) so they need raw MMIO at base+off,
// exactly like gadc::new()'s pmu_rmw + delay_us(...) staging.
const LSADC_BASE: usize = 0x4400_C000;
fn delay_us(us: u32) { for _ in 0..us.saturating_mul(40) { core::hint::spin_loop(); } }
impl LsAdc<'_> {
    /// Run the full silicon power-up: simu cfg -> staged da_lsadc_en ramp
    /// (timed) -> calibration -> release da_lsadc_rstn. After this the FIFO
    /// can fill; before it, conversions never start. Idempotent.
    pub fn power_up(&mut self) {
        // SAFETY: fixed LSADC MMIO; rwreg_1..3 not modeled in PAC.
        unsafe {
            wr(LSADC_BASE + RWREG_1, 0x155240); // simu_cfg1
            wr(LSADC_BASE + RWREG_2, 0x5);      // simu_cfg2
            wr(LSADC_BASE + RWREG_3, 0x100);    // simu_cfg3
        }
        self.or_analog_enable(0x7000); delay_us(500);
        self.or_analog_enable(0xE7F);  delay_us(300);
        self.or_analog_enable(0x100);
        self.or_analog_enable(0x80);
        self.calibrate();               // offset/cap/gain auto-cal
        self.enable();                  // da_lsadc_rstn release (existing)
    }
    fn or_analog_enable(&mut self, bits: u16) {
        self.regs().lsadc_ctrl_11().modify(|r, w| unsafe {
            w.da_lsadc_en().bits(r.da_lsadc_en().bits() | bits) });
    }
}

// CLASS B — REMOVE the raw overwrite. A single `w.da_lsadc_en().bits(bits)`
// (lsadc.rs:135-137) overwrites the whole 16-bit field and cannot reproduce
// the timed |= 0x7000/0xE7F/0x100/0x80 ramp; it clears bits a prior step set.
// Replaced by the internal staged or_analog_enable() inside power_up() above.
// Public API: delete set_analog_enable; the only correct way to drive
// da_lsadc_en is power_up(). ("no-change" to the FIELD = remove the surface.)
#[deprecated(note = "use power_up(); raw overwrite cannot stage the AFE ramp")]
pub fn set_analog_enable(&mut self, _bits: u16) { /* removed in 0.5.0 */ }

// CLASS B — vendor tree has ZERO writes to cic_osr/cfg_cic_filter_en; the
// supported path uses the cali pipeline, not CIC. No validated working OSR
// range exists, and output only reaches the FIFO if cfg_data_sel.data_sel=1.
// Keep field width (u8, no truncation) but mark experimental + reject OSR=0,
// and couple it to data_sel so a structurally-valid enable can't no-op.
#[deprecated(note = "CIC path unused by vendor SDK; no validated OSR range; \
                     needs data_sel=processed. Experimental, unvalidated on silicon.")]
pub fn enable_cic_filter(&mut self, osr: u8) -> Result<(), AdcError> {
    if osr == 0 { return Err(AdcError::InvalidOsr); } // zero OSR = no decimation
    self.set_data_select(true);                       // enforce the coupling
    let r = self.regs();
    unsafe { r.cfg_cic_osr().write(|w| w.cic_osr().bits(osr)); }
    r.cfg_cic_filter_en().write(|w| w.cic_filter_en().set_bit());
    Ok(())
}

