// CLASS C — enabling channel N must also provision its analog pad
// (pull-disable + PIN_MODE_0 analog mux + INPUT dir) on GPIO_07..GPIO_12 for
// ch0..5, else the channel reads a floating/digital pad. Encode the mapping
// and provision it inside configure_scan (board precondition, not typeable).
const CH_TO_GPIO: [u8; 6] = [7, 8, 9, 10, 11, 12]; // GPIO_07..GPIO_12
fn provision_channel_pad(ch: AdcChannel) {
    let pin = CH_TO_GPIO[ch as usize];
    // pull-disable + PIN_MODE_0 (analog mux) + input dir, via io_config/gpio HAL.
    crate::io_config::set_pull(pin, Pull::None);
    crate::io_config::set_mode(pin, PinMode::Mode0);
    // input direction is the lsadc default for an analog pad.
}
