/// Error returned when a bounded conversion wait gives up.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum AdcError { Timeout, InvalidOsr }
impl LsAdc<'_> {
    /// Vendor bound: COUNT_THRESHOLD = 1000 poll iterations.
    const COUNT_THRESHOLD: u32 = 1000;
    /// Blocking read with the vendor's bounded wait instead of spinning forever.
    pub fn read_sample_timeout(&mut self) -> Result<AdcSample, AdcError> {
        self.start_scan();
        let mut n = 0;
        while !self.data_ready() {
            n += 1;
            if n >= Self::COUNT_THRESHOLD { return Err(AdcError::Timeout); }
        }
        self.read_sample().ok_or(AdcError::Timeout)
    }
}
// async: bound ConvFuture with an embassy-time timeout (or a poll budget)
// so a never-firing IRQ72 cannot park forever:
//   pub async fn read_async(&mut self) -> Result<AdcSample, AdcError>

/// A validated timer load count: a non-zero count of TIMER_CLOCK_HZ ticks that
/// fits the full 32-bit TIMER%s_LOAD_COUNT register. Construction rejects both
/// the zero-period (class B: no working output) and over-range (class D: the old
/// silent clamp to u32::MAX) cases, so configure()/start() can never be handed a
/// load the hardware cannot run for the requested time.
#[derive(Clone, Copy, Debug, PartialEq, Eq, PartialOrd, Ord)]
pub struct TimerTicks(u32);

impl TimerTicks {
    /// Wrap a raw down-counter load. `None` for 0 (a 0 load does NOT yield a
    /// zero-length delay on the V150 down-counter: it fires immediately or wraps
    /// 2^32 — no usable output; vendor rejects it, timer.c:425).
    pub const fn from_ticks(ticks: u32) -> Option<Self> {
        if ticks == 0 { None } else { Some(TimerTicks(ticks)) }
    }
    /// The largest representable microsecond request at TIMER_CLOCK_HZ
    /// (vendor uapi_timer_get_max_us = u32::MAX / (clock/1e6); = 178_956_970 us
    /// (~178.96 s) at 24 MHz, 107_374_182 us (~107.37 s) at 40 MHz).
    pub const fn max_micros() -> u64 {
        u32::MAX as u64 / (TIMER_CLOCK_HZ as u64 / 1_000_000)
    }
    /// us -> ticks. `None` for 0 us (zero period) or us > max_micros() (would
    /// exceed the 32-bit load) — REJECTS instead of clamping to u32::MAX.
    pub const fn try_from_micros(us: u32) -> Option<Self> {
        let ticks = TIMER_CLOCK_HZ as u64 * us as u64 / 1_000_000;
        if ticks == 0 || ticks > u32::MAX as u64 { None } else { Some(TimerTicks(ticks as u32)) }
    }
    /// ms -> ticks; same accept/reject rule (>~178_956 ms @24 MHz rejected).
    pub const fn try_from_millis(ms: u32) -> Option<Self> {
        let ticks = TIMER_CLOCK_HZ as u64 * ms as u64 / 1_000;
        if ticks == 0 || ticks > u32::MAX as u64 { None } else { Some(TimerTicks(ticks as u32)) }
    }
    pub const fn ticks(self) -> u32 { self.0 }
}
// start() / configure() retyped to take TimerTicks (see zero-load row):
pub fn start(&mut self, count: TimerTicks) {
    self.driver.configure(self.channel, TimerMode::OneShot, count);
    self.driver.enable(self.channel);
}
pub fn try_start_micros(&mut self, us: u32) -> Option<()> {
    self.start(TimerTicks::try_from_micros(us)?); Some(())
}

/// configure() now takes the validated TimerTicks (never 0), so a zero load is
/// unrepresentable at the call site rather than being written verbatim then
/// enabled (the old src/timer.rs:46-61 path).
pub fn configure(&self, n: usize, mode: TimerMode, load: TimerTicks) {
    let r = self.regs();
    let lv = load.ticks(); // guaranteed >= 1
    match n {
        0 => r.timer0_load_count(0).write(|w| unsafe { w.bits(lv) }),
        1 => r.timer0_load_count(1).write(|w| unsafe { w.bits(lv) }),
        2 => r.timer0_load_count(2).write(|w| unsafe { w.bits(lv) }),
        _ => unreachable!(),
    };
    // ... mode write: see int_mask RMW row
}
// PeriodicTimer::start likewise takes TimerTicks. The async path's ticks.max(1)
// (src/timer.rs:467) is replaced by TimerTicks::from_ticks(ticks)
//   .unwrap_or(TimerTicks(1)) so the two paths share one non-zero invariant.

impl TimerTicks {
    /// ns -> ticks. `None` for 0 ns OR any sub-tick request (< ~41.7 ns @24 MHz,
    /// < ~25 ns @40 MHz) that rounds to 0 ticks — the case the blocking impl
    /// silently no-op'd (src/timer.rs:255-262) and the async impl silently
    /// rounded up to 1 (src/timer.rs:492-495+467). Now both decide explicitly.
    pub const fn try_from_nanos(ns: u32) -> Option<Self> {
        let ticks = TIMER_CLOCK_HZ as u64 * ns as u64 / 1_000_000_000;
        if ticks == 0 || ticks > u32::MAX as u64 { None } else { Some(TimerTicks(ticks as u32)) }
    }
}
// Blocking trait impl keeps embedded-hal semantics but makes the sub-tick
// behaviour a single documented choice (round UP to one tick, the smallest
// real delay, matching the async path) instead of two silently different ones:
fn delay_ns(&mut self, ns: u32) {
    let ticks = TimerTicks::try_from_nanos(ns)
        .unwrap_or(TimerTicks(1)); // sub-tick -> one tick (>= request, never a no-op)
    self.start(ticks);
    self.wait();
}

/// Runtime timer counting clock, read from the HW_CTL TCXO strap the same way
/// uart_boot_clock_hz() already does (soc/ws63.rs:90-98). This is a class-C
/// UNENFORCED BOARD PRECONDITION that a const cannot express: the vendor selects
/// REQ_24M vs REQ_40M at runtime from get_tcxo_freq() (clock_init.c:147-160).
#[cfg(feature = "chip-ws63")]
pub fn timer_clock_hz() -> u32 {
    // HW_CTL bit0: 1 = 24 MHz TCXO, 0 = 40 MHz (vendor soc_porting.h CLK24M_TCXO).
    const HW_CTL: usize = 0x4000_0014;
    let hw_ctl = unsafe { core::ptr::read_volatile(HW_CTL as *const u32) };
    if hw_ctl & 0x1 == 1 { 24_000_000 } else { 40_000_000 }
}
// The const TIMER_CLOCK_HZ stays for the typed bounds (const fns need it), but
// the runtime conversions in try_from_micros/millis are offered in a runtime
// variant that takes the measured clock so a 40 MHz board is not silently 1.67x
// too long:
impl TimerTicks {
    pub fn try_from_micros_at(us: u32, clock_hz: u32) -> Option<Self> {
        let ticks = clock_hz as u64 * us as u64 / 1_000_000;
        if ticks == 0 || ticks > u32::MAX as u64 { None } else { Some(TimerTicks(ticks as u32)) }
    }
}
// DOC-AND-GUARD: TimerDriver::new() / module docs MUST state: "TIMER_CLOCK_HZ
// (const) is correct only on a 24 MHz-crystal board; on a 40 MHz board pass
// timer_clock_hz() to *_at(). BS21 32 MHz is unconfirmed (soc/bs21.rs:28)."

// Replace the blind `w.bits(((mode as u32)&0x3)<<1)` (src/timer.rs:54-60) with a
// read-modify-write using the NAMED PAC fields (enable=bit0, mode=bits1:2,
// int_mask=bit3, ws63-pac lib.rs:23628/23633/23638), matching vendor RMW set_mode
// (hal_timer_v150_regs_op.h:67-73) so int_mask and enable survive a reconfigure:
let set_mode = |ctl: &TimerControl| ctl.modify(|_, w| unsafe { w.mode().bits(mode as u8 & 0x3) });
match n {
    0 => set_mode(r.timer0_control(0)),
    1 => set_mode(r.timer0_control(1)),
    2 => set_mode(r.timer0_control(2)),
    _ => unreachable!(),
};
// modify() preserves int_mask/enable/cnt_* — only the 2-bit mode field changes.
// No type needed: TimerMode (enum, 0/1) already bounds the field (class A N/A).
// 'result' here = the behavioural correctness fix (preserve a register bit),
// not a new Result return; the IRQ-routing precondition stays a doc note.

/// The Periodic variant programs control.mode = 1 and TRUSTS the TIMER_V150 to
/// auto-reload. The vendor C SDK NEVER does this: hal_timer_v150_config_load
/// always forces ONE_SHOT (hal_timer_v150.c:80) and reloads in software on each
/// IRQ (driver/timer.c:170-185). So this path is NOT exercised by the
/// silicon-validated vendor flow and MUST be confirmed on a board before it is
/// trusted (mode=1 may still need the cnt/load handshake or may not reload).
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum TimerMode { OneShot = 0, Periodic = 1 } // unchanged; enum already correct
// No code change to the enum. Add a #[doc] + a debug_assert-free guard note on
// PeriodicTimer::start documenting the on-board-confirmation requirement; do NOT
// fake a software-reload here (that is a separate feature, not a config
// tightening). If silicon proves mode=1 does not reload, the fix is to remove
// Periodic or implement vendor-style software reload behind the async IRQ hook.

/// A validated DMA transfer length in source-width beats.
/// Existence of a value guarantees it fits the 12-bit `trans_size` field
/// (1..=4095) — there is no representable count that the hardware truncates.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct TransferCount(u16);

impl TransferCount {
    /// Max programmable beats: the trans_size field is 12 bits, and the
    /// vendor rejects `transfer_num >= HAL_DMA_CH_MAX_TRANSFER_NUM (4096)`.
    pub const MAX: u16 = 4095;

    /// Construct from a beat count; `None` if 0 (no-op) or > 4095 (would wrap).
    pub const fn from_count(beats: u16) -> Option<Self> {
        if beats >= 1 && beats <= Self::MAX {
            Some(TransferCount(beats))
        } else {
            None
        }
    }

    /// The raw beat count (always 1..=4095).
    pub const fn count(self) -> u16 {
        self.0
    }
}

// configure_channel signature changes from `transfer_size: u16` to
// `transfer_size: TransferCount`; the body drops the `& 0xFFF` mask and
// writes `transfer_size.count() as u32` directly (the value is pre-validated).
pub fn configure_channel(&mut self, channel: u8, src_addr: u32, dst_addr: u32,
    transfer_size: TransferCount, config: &DmaChannelConfig) { /* ... no mask ... */ }

// CLASS C: the controller's missing 'self-service' is cache maintenance, the
// DMA analogue of PWM self-enabling its own clock gate. Because src/dst are raw
// u32 addresses (full 32-bit fields, intentionally — a DMA buffer may be any
// physical address incl. a peripheral FIFO that must NOT be cache-touched), a
// type cannot know whether a given address is a cacheable RAM buffer. So make
// configure_channel self-sufficient with a documented, overridable maintenance
// step keyed off flow_control, and document the precondition for the raw path.

pub fn configure_channel(&mut self, channel: u8, src_addr: u32, dst_addr: u32,
    transfer_size: TransferCount, config: &DmaChannelConfig) {
    // ... write addrs / control / ch_cfg ...

    // Self-service coherence (mirrors vendor hal_dma_v151_enable's
    // osal_dcache_flush_all() before ch_en). Only clean the SOURCE when it is a
    // RAM buffer the CPU wrote (src_inc => incrementing RAM, not a fixed
    // peripheral FIFO); the caller invalidates the DEST after completion.
    #[cfg(target_arch = "riscv32")]
    if config.src_inc {
        let bytes = transfer_size.count() as usize
            * width_bytes(config.src_width);
        // SAFETY: src is the caller-supplied source buffer for this transfer.
        unsafe { crate::cache::clean_range(src_addr as usize, bytes); }
    }

    // kick: dmac_en_chns |= 1 << ch ...
}

/// # Cache coherence
/// WS63 has a non-coherent D-cache. `configure_channel` cleans an incrementing
/// RAM **source** to memory before kicking. The caller MUST
/// `cache::invalidate_range(dst_addr, bytes)` AFTER the transfer completes,
/// before reading the destination, OR pass cache-line (32B) aligned buffers and
/// rely on this clean. Peripheral-FIFO addresses (src_inc/dst_inc = false) are
/// not cache-maintained by design.

const fn width_bytes(w: TransferWidth) -> usize {
    match w { TransferWidth::Width8 => 1, TransferWidth::Width16 => 2, TransferWidth::Width32 => 4 }
}

// Replace the two public raw u8 fields with the existing DmaPeripheral enum
// (already the only safe path; the builders mem_to_peripheral/peripheral_to_mem
// already set one side). A raw u8 should not be publicly writable.
#[cfg(feature = "chip-ws63")]
pub struct DmaChannelConfig {
    pub(crate) src_peripheral: Option<DmaPeripheral>, // None => Tie0 (id 0)
    pub(crate) dst_peripheral: Option<DmaPeripheral>,
    pub flow_control: FlowControl,
    // ... other fields unchanged ...
}

// configure_channel encodes the validated nibble (request_id() is 0..=14, all
// <= 0x0F by construction — DmaPeripheral's discriminants are the dma_porting.h
// indices that fit the 4-bit field), so the `& 0x0F` mask is dropped:
let src_id = config.src_peripheral.map_or(0, DmaPeripheral::request_id);
let dst_id = config.dst_peripheral.map_or(0, DmaPeripheral::request_id);
ch_cfg |= (src_id as u32) << 1;   // s_peripheral [1:4], no mask needed
ch_cfg |= (dst_id as u32) << 5;   // d_peripheral [5:8]

// On chip-bs2x (no DmaPeripheral enum / no peripheral-paced table in tree),
// keep the fields absent or hard-tie to 0: BS2X DMA is mem-to-mem only here.

// CLASS C clock-gate: the auto-gate bypass is the controller's ONLY clock
// provisioning (DMA has no separate CKEN gate — clock.rs:16 lists Dma/Sdma
// cken_info = None), so the address MUST be correct per chip. Gate the
// constant by chip feature instead of poking a WS63 offset on BS2X.
impl DmaInstance for Dma0 {
    // WS63: M_DMA auto clock-gate bypass (DMA_CLK_AUTO_CTRL_REG bit 19),
    // dma_porting.c DMA_CLK_AUTO_CTRL_REG 0x44000244 / DMA_CLK_ON_MASK 0x80000.
    #[cfg(feature = "chip-ws63")]
