/// A validated I2C SCL frequency for the WS63 custom v150 controller.
///
/// Holds the *programmable* half-period count directly: `half = pclk/(4*hz)`,
/// which is written into BOTH the 16-bit `i2c_scl_h.scl_h` and `i2c_scl_l.scl_l`
/// fields (ws63-pac SclHW/SclLW = FieldWriter<..,16,u16>). Because a value of this
/// type only exists when `1 <= half <= 0xFFFF`, an out-of-range frequency is
/// rejected at construction instead of being silently truncated into the 16-bit
/// field (the old `w.bits(half)` wrote a full u32 and the HW kept only bits 0:15).
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct I2cFreq(u16);

impl I2cFreq {
    /// Vendor hard cap: baudrate must be <= 3.4 MHz HS limit and != 0
    /// (fbb_ws63 i2c.c:933, I2C_HS_MODE_BAUDRATE_HIGH_LIMIT = 3400*1000).
    pub const MAX_HZ: u32 = 3_400_000;

    /// Derive the SCL half-period from a source clock `pclk` and target `hz`.
    /// `None` when `hz == 0`, `hz > MAX_HZ`, the half-period rounds to 0
    /// (`hz` too fast -> dead bus), or it would exceed the 16-bit field
    /// (`hz` too slow -> truncation). Equivalent band for pclk=24 MHz:
    /// 92 Hz ..= 3_400_000 Hz.
    pub const fn try_from_hz(pclk: u32, hz: u32) -> Option<Self> {
        if hz == 0 || hz > Self::MAX_HZ {
            return None;
        }
        let half = pclk / (4 * hz); // u32 math, hz>=1 so divisor>=4
        if half == 0 || half > u16::MAX as u32 {
            return None;
        }
        Some(I2cFreq(half as u16))
    }

    /// Wrap a raw half-period count directly (escape hatch / scope-tuning). `None` for 0.
    pub const fn from_half_count(half: u16) -> Option<Self> {
        if half == 0 { None } else { Some(I2cFreq(half)) }
    }

    /// The 16-bit half-period written to scl_h and scl_l.
    pub const fn half(self) -> u16 { self.0 }
}

// new_i2c0(_i2c: I2c0<'d>, freq: I2cFreq) -> Self  (freq.half() goes straight
// to the now-typed field writers via `w.scl_h().bits(freq.half())`).

// Same I2cFreq::try_from_hz as above. The two clauses that close this surface:
//   if hz == 0 || hz > Self::MAX_HZ { return None; }   // vendor 3.4 MHz cap
//   if half == 0 { return None; }                       // pclk/(4*hz)==0 guard
// MAX_HZ = 3_400_000 makes the dead-bus band (hz > pclk/4) entirely
// unreachable: it is rejected long before half reaches 0. The explicit
// `half == 0` clause is kept as defence-in-depth so the type is correct
// even if a future pclk re-tuning raises MAX_HZ.
const _: () = assert!(I2cFreq::MAX_HZ <= 24_000_000 / 4); // 3.4M < 6M, always-true guard

// DELETE the zero-guard line entirely. The clamp existed only to avoid a
// div-by-zero in the old infallible path; with I2cFreq the divide moves into
// try_from_hz, which returns None for hz==0 BEFORE dividing:
//   if hz == 0 || hz > Self::MAX_HZ { return None; }
// configure_i2c no longer takes a raw freq at all -- it takes I2cFreq and just
// writes freq.half(), so there is no clamp and no div-by-zero to guard.
fn configure_i2c(idx: u8, freq: I2cFreq) {
    let r = i2c_regs(idx);
    let half = freq.half();
    r.i2c_scl_h().write(|w| w.scl_h().bits(half));
    r.i2c_scl_l().write(|w| w.scl_l().bits(half));
    // ... ctrl unchanged ...
}

// The fallibility lives in the TYPE, not the constructor, exactly like PWM
// (PwmPeriod::try_from_hz -> Option, then PwmChannel::configure is infallible).
// new_i2c* stay `-> Self` but now REQUIRE a pre-validated I2cFreq, so the
// out-of-range band is unrepresentable at the call site:
impl<'d> I2c<'d, I2c0<'d>> {
    pub fn new_i2c0(_i2c: I2c0<'d>, freq: I2cFreq) -> Self {
        configure_i2c(0, freq);
        Self { idx: 0, _peripheral: PhantomData }
    }
}
// Caller:
//   let freq = I2cFreq::try_from_hz(soc::chip::I2C_CLOCK_HZ, 100_000)
//       .expect("100 kHz is in-band");
//   let i2c = I2c::new_i2c0(p.I2C0, freq);
// 'constructs' now implies 'programmable' -- the same guarantee PWM gives.

// The clock value is a board/silicon fact a type cannot prove, so keep it a
// documented const but (a) thread it THROUGH the type so the predicate stays
// correct whatever the answer, and (b) flag the uncertainty loudly like PWM's
// PWM_CLOCK_HZ note. The constructor uses the canonical const; the newtype
// takes pclk as a parameter so a corrected value needs ONE edit:
///
/// # Clock uncertainty (needs on-board confirmation)
/// Three values coexist in-tree: 24 MHz (this const), 40 MHz (vendor porting
/// default i2c_porting.c:25), 80 MHz (HAL clock_init.rs:68). I2cFreq::try_from_hz
/// is parameterised on `pclk`, so the accept/reject band is correct for whichever
/// silicon confirms; only the const below (and the documented edges) move.
pub const I2C_CLOCK_HZ: u32 = TCXO_HZ; // 24 MHz -- UNVERIFIED, see above
// Optional const-eval tripwire so a future bad edit is caught at build time:
const _: () = assert!(I2cFreq::try_from_hz(I2C_CLOCK_HZ, 100_000).is_some());

// Fold the vendor cfg_clk's `-1` (counter is N+1 cycles) into I2cFreq so the
// programmed rate matches the request; keep symmetric h==l weighting (the driver
// already programs scl_h==scl_l, a valid 50% point of the vendor formula):
//   let half = pclk / (4 * hz);
//   let half = half.saturating_sub(1);     // vendor hal_i2c_v150_cfg_clk -1
//   if half == 0 { return None; }          // now also rejects the half==1 edge
// Document that the symmetric high/low split is the chosen weighting; full
// asymmetric scl_h/(scl_h+scl_l) is deferred (low severity, 50% is in-spec).
// NOTE: keep this as a SEPARATE follow-up from the truncation fix -- the -1 is a
// rate-skew refinement, not a correctness gate, and changes the boundary value
// (the smallest accepted hz now needs half>=2 after the -1).

// Keep the safe Speed enum; replace the magic constants in scl_params with a
// const derivation from soc::chip::I2C_CLOCK_HZ so the rate tracks the real clock
// instead of a baked-in ~32 MHz assumption. DesignWare nominal:
//   hcnt ~= i2c_clk / (target_hz * 2);  lcnt slightly longer for SS/FS asymmetry.
const fn scl_params(speed: Speed) -> (u32, u32, u32) {
    let clk = crate::soc::chip::I2C_CLOCK_HZ; // BS2X TCXO = 32_000_000
    match speed {
        // SS=1: target 100 kHz; FS=2: target 400 kHz. (-7/-1 are the DW spike+sync
        // adjustments; tune against fbb_bs2x hal_i2c_v151 once that source lands.)
        Speed::Standard => (1, clk / 100_000 / 2, clk / 100_000 / 2 + 30),
        Speed::Fast =>     (2, clk / 400_000 / 2, clk / 400_000 / 2 + 10),
    }
}
// At clk=32 MHz this reproduces ~160/190 and ~40/50, so silicon behaviour is
// unchanged today; if the BS2X I2C clock is later corrected the rate follows.
