impl TcxoFreq {
    /// HW_CTL @0x4000_0014 bit0 TCXO-frequency strap.
    /// CLK24M_TCXO = 1, CLK40M_TCXO = 0 (vendor soc_porting.h:22-23),
    /// matching the HAL's own soc/ws63.rs:97 uart_boot_clock_hz reader.
    const REFCLK_FREQ_STATUS_MASK: u32 = 0x1;

    /// Read the strap. Always succeeds (the strap is a fixed readable MMIO bit),
    /// but it is now a *measurement*, not a guess — see [`SystemClocks`] which
    /// has no fabricator.
    pub fn detect() -> Self {
        // SAFETY: HW_CTL is a fixed read-only strap, always readable on WS63.
        let hw_ctl = unsafe { HW_CTL.read_volatile() };
        // FIX: bit0 == 1 -> 24 MHz (was inverted: returned MHz24 on bit0 == 0).
        if hw_ctl & Self::REFCLK_FREQ_STATUS_MASK == Self::REFCLK_FREQ_STATUS_MASK {
            TcxoFreq::MHz24
        } else {
            TcxoFreq::MHz40
        }
    }
}
// Also fix the doc table clock_init.rs:53 to read 'bit[0]: 1=24MHz, 0=40MHz'.

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ClockInitError {
    /// PLL never locked within the retry budget — NO source mux was switched.
    PllNotLocked,
}

/// Verify-then-switch: poll PLL lock FIRST; only switch source muxes after.
pub fn init_clocks(
    sram: ExecFromSram,        // see XIP surface
    cldo_crg: CldoCrg<'_>,     // owned, see precondition surface
    sys_ctl0: &SysCtl0<'_>,
) -> Result<SystemClocks, ClockInitError> {
    let tcxo_freq = TcxoFreq::detect();
    // ── Step 0 (was step 4): require lock BEFORE any mux switch. ──
    if wait_pll_lock(30, 1000) != PllStatus::Locked {
        // Nothing switched; every domain still on its safe boot source.
        return Err(ClockInitError::PllNotLocked);
    }
    // PLL proven up — now switch flash/UART/SPI muxes (old steps 1-3),
    // then apply per-TCXO dividers (see divider surface).
    switch_sources_to_pll(&cldo_crg, tcxo_freq);
    Ok(SystemClocks { cpu_clk: SYSTEM_CLOCK_HZ, pclk: SYSTEM_CLOCK_HZ, tcxo_freq, pll_locked: true })
}

/// Capability token proving the caller is executing from SRAM, not XIP from
/// SPI flash. init_clocks reconfigures the live SFC controller (CMU_NEW_CFG1
/// 0x1->0x3, CLK_SEL bit18); doing that while fetching instructions from that
/// same flash glitches the fetch clock and hangs the core.
///
/// There is no register bit that proves 'PC is in SRAM', so this is a
/// doc-and-guard-backed *capability*: only an unsafe constructor mints it, and
/// the safe init_clocks signature REQUIRES it, moving the precondition from
/// prose (soc/ws63.rs:66) into the type. A pure-XIP example simply cannot call
/// init_clocks because it cannot honestly produce this token.
pub struct ExecFromSram(());

impl ExecFromSram {
    /// # Safety
    /// Caller must guarantee the current execution (and the init_clocks call)
    /// runs from SRAM, with no instruction fetch served by the SFC/flash whose
    /// clock init_clocks reconfigures. Relocate .text to SRAM first.
    pub const unsafe fn assume() -> Self { ExecFromSram(()) }
}
// init_clocks(sram: ExecFromSram, ...) consumes it (see ordering surface).

// Take the CRG BY VALUE so the type system proves exclusive ownership for the
// duration of the (non-atomic read-modify-write) CLK_SEL/CKEN/DIV sequence,
// then hand it back so later divider config can use it.
pub fn init_clocks(
    sram: ExecFromSram,
    cldo_crg: CldoCrg<'_>,        // BY VALUE — was &CldoCrg, ignored as _cldo_crg
    sys_ctl0: &SysCtl0<'_>,       // now actually read for PLL status, not _sys_ctl0
) -> Result<(SystemClocks, CldoCrg<'_>), ClockInitError> {
    // ... uses cldo_crg.register_block() instead of a raw 0x4400_1134 pointer
    //     so the borrow checker forbids a concurrent CldoCrg holder. ...
    Ok((clocks, cldo_crg))
}

// The PLL power-up (vendor open_rf_power + DBG_CMU_XO_PD=ONEN_RF_PLL,
// clock_init.c:59-138) touches the RF/analog island. It is NOT a clean MMIO
// idempotent sequence the HAL has validated on silicon, so we do NOT fabricate
// a power-up; we ENFORCE the precondition by the lock check (verify-then-switch
// surface) and document the assumption explicitly:

/// # Precondition
/// The boot ROM / flashboot must already have powered and configured the CPU
/// FNPLL. init_clocks does NOT power the PLL; it only VERIFIES lock
/// (REG_EXCEP_RO_RG bit12) and, on success, switches source muxes. On a cold
/// custom loader where the PLL is down, init_clocks returns
/// Err(ClockInitError::PllNotLocked) and leaves every clock on its boot source.
/// To bring the PLL up from cold, run the vendor open_rf_power/switch_clock RF
/// sequence first (not yet ported — tracked separately).
// (No type can express 'analog PLL is physically powered'; the honest move is
//  the lock-gate Err + this doc, replacing the silent assumed()=true guess.)

/// Apply the TCXO-frequency-dependent dividers the vendor switch_clock /
/// set_uart_tcxo_clock_period program, so a driver built after init_clocks
/// samples/ticks at the right rate (the 'construct -> clocked' guarantee for
/// TRNG/TSENSOR/I2C/Timer/WDT, the clock-domain analogue of PWM/SPI self-enable).
fn apply_tcxo_dividers(cldo_crg: &CldoCrg<'_>, tcxo: TcxoFreq) {
    // CLDO_CRG_DIV_CTL9[8:6] TRNG divider, CLDO_CRG_DIV_CTL7[11:6] TSENSOR divider.
    let (trng_div, tsensor_div): (u32, u32) = match tcxo {
        TcxoFreq::MHz24 => (2, 0x18),  // div 2 / 0x18 for 24 MHz
        TcxoFreq::MHz40 => (4, 0x28),  // div 4 / 0x28 for 40 MHz
    };
    // RMW DIV_CTL9 bits[8:6] = trng_div; DIV_CTL7 bits[11:6] = tsensor_div.
    // set_uart_tcxo_clock_period: I2C/timer/WDT counting clock = tcxo.hz()
    // (REQ_24M / REQ_40M) — recorded in SystemClocks.tcxo_freq for the tick math.
    // ... volatile RMW with masked fields so neighbouring bits are preserved ...
}
// Called from init_clocks AFTER the lock check + source switch, before Ok(...).

/// Why a peripheral has no individually-mapped clock gate. Replaces the
/// ambiguous `None` (which conflated 'no gate exists' with 'gate exists but
/// unmapped') so a consumer (safety.rs drift checks / future gating code) can
/// tell the two apart.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Ungated {
    /// SDK confirms the block is not individually gated; rely on reset-default.
    NoIndividualGate,
    /// A gate plausibly exists but is NOT attested by SVD/porting code, so we
    /// refuse to fabricate a bit (e.g. Spi1: shares the SPI domain Spi0 gates at
    /// CKEN_CTL1[25], but no independent Spi1 bit is attested).
    GateUnverified,
}

impl Peripheral {
    pub fn cken_info(&self) -> Result<(u8, u8), Ungated> {
        match self {
            Peripheral::Pwm  => Ok((0, 2)),
            Peripheral::I2s  => Ok((0, 12)),
            Peripheral::Uart0 => Ok((1, 18)),
            Peripheral::Uart1 => Ok((1, 19)),
            Peripheral::Uart2 => Ok((1, 20)),
            Peripheral::Spi0 => Ok((1, 25)),
            Peripheral::Spi1 => Err(Ungated::GateUnverified),
            Peripheral::I2c0 | Peripheral::I2c1 | Peripheral::Timer
            | Peripheral::Lsadc | Peripheral::Tsensor | Peripheral::Trng
            | Peripheral::SecurityGroup | Peripheral::Dma | Peripheral::Sdma
            | Peripheral::Sfc => Err(Ungated::NoIndividualGate),
        }
    }
}

