// Re-encode the enum so the discriminant IS the real 3-bit HW mem_if_type wire value.
// Reserved encodings 3 and 4 are simply not variants, so they are unrepresentable.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
#[repr(u8)]
pub enum SpiIfType {
    /// 000 - single-line standard SPI.
    Standard   = 0b000, // 0
    /// 001 - dual-OUTPUT (data on 2 lines, cmd/addr single). HW label is Dual-Output.
    DualOutput = 0b001, // 1
    /// 010 - dual-IO (cmd single, addr+data on 2 lines).
    DualIo     = 0b010, // 2
    /// 101 - quad-OUTPUT (data on 4 lines).
    QuadOutput = 0b101, // 5
    /// 110 - quad-IO (addr+data on 4 lines, e.g. 0xEB fast read).
    QuadIo     = 0b110, // 6
}
impl SpiIfType {
    #[inline] pub const fn bits(self) -> u32 { self as u32 } // already the 3-bit field value
}
// configure_bus then writes `config.read_if_type.bits()` directly (no `& 0x07` needed,
// every variant is already <=6 and in-range). DualIO/DualIOCont/QuadIO=3/QuadIOCont=4 are deleted.

// A BusConfig that cannot be constructed without committing to enabling the bus halves,
// and a configure_bus that does the vendor's read-modify-write so the two halves and the
// enable bits coexist instead of clobbering each other.
pub struct BusConfig { /* existing fields unchanged */ }
impl BusConfig {
    /// Build a read+write bus config. Both bus halves are ENABLED unconditionally
    /// (vendor RD_ENABLE/WR_ENABLE), matching a working XIP/mem-mapped setup.
    pub const fn new(/* read_if_type, read_dummy_bytes, ... write_instruction */) -> Option<Self> {
        // reject dummy>7 (3-bit), prefetch>3 (2-bit) here so the later pack needs no mask
        // ... returns None on any out-of-field input ...
    }
}
pub fn configure_bus(&mut self, config: &BusConfig) {
    let r = self.regs();
    // READ half: RMW preserving the write half + write-enable, then OR read fields + RD_ENABLE.
    r.bus_config1().modify(|_, w| unsafe {
        w.rd_mem_if_type().bits(config.read_if_type.bits() as u8)
         .rd_dummy_bytes().bits(config.read_dummy_bytes)
         .rd_prefetch_cnt().bits(config.read_prefetch_cnt)
         .rd_ins().bits(config.read_instruction)
         .rd_enable().set_bit()   // bit31 - was never set
    });
    // WRITE half: second modify preserves the read half just written.
    r.bus_config1().modify(|_, w| unsafe {
        w.wr_mem_if_type().bits(config.write_if_type.bits() as u8)
         .wr_dummy_bytes().bits(config.write_dummy_bytes)
         .wr_ins().bits(config.write_instruction)
         .wr_enable().set_bit()   // bit30 - was never set
    });
    // BUS_CONFIG2 (wip_locate, bus_ddr_mode dummy) gets vendor defaults via a third modify.
}

