/// DMA transfer length for the SFC bus DMA. Stores n = len-1 because the
/// bus_dma_len register encodes (n+1) bytes. Non-zero by construction.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct DmaLen(u32); // holds the register value n = bytes-1
impl DmaLen {
    /// `bytes` = actual transfer size. Rejects 0 (would wrap to a ~1GB transfer)
    /// and anything that does not fit the 30-bit (n+1) field.
    pub const fn from_bytes(bytes: u32) -> Option<Self> {
        if bytes == 0 || bytes > (1 << 30) { return None; } // max encodable = 2^30 bytes
        Some(DmaLen(bytes - 1))
    }
    /// The raw 30-bit register value (already bytes-1).
    #[inline] pub const fn field(self) -> u32 { self.0 } // <= 0x3FFF_FFFF
    #[inline] pub const fn bytes(self) -> u32 { self.0 + 1 }
}
// bus_dma_start signature becomes: fn bus_dma_start(&mut self, mem_addr: MemAddr, flash_addr: u32, length: DmaLen, read: bool)
// and writes `r.bus_dma_len().write(|w| w.bits(length.field()))` -- no `length-1`, no `& mask`.

/// A memory address inside the SFC system-bus DMA window. Construction validates
/// the range so an out-of-window DMA target is unrepresentable.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct MemAddr(u32);
impl MemAddr {
    pub const SFC_MCPU_START: u32 = 0x0020_0000;
    pub const SFC_MCPU_END:   u32 = 0x009F_FFFF; // vendor SFC_MCPU_END (tighter than PAC 0xBFFFFF doc)
    pub const fn new(addr: u32) -> Option<Self> {
        if addr >= Self::SFC_MCPU_START && addr <= Self::SFC_MCPU_END { Some(MemAddr(addr)) } else { None }
    }
    #[inline] pub const fn addr(self) -> u32 { self.0 }
}
// bus_dma_start takes MemAddr; combined with DmaLen, a caller could still program a
// (mem_addr + len) that overruns SFC_MCPU_END, so bus_dma_start additionally returns
// Result<(), SfcError> and checks `mem.addr().checked_add(len.bytes()-1) <= SFC_MCPU_END`,
// returning SfcError::AddressOverstep (mirrors vendor ERRCODE_SFC_ADDRESS_OVERSTEP).

// Not a value to type; it is a fixed register-write sequence the driver omits.
// Fold the vendor preamble into bus_dma_start so 'construct DmaLen/MemAddr -> correct DMA':
pub fn bus_dma_start(&mut self, mem: MemAddr, flash_addr: u32, len: DmaLen, read: bool)
    -> Result<(), SfcError>
{
    let r = self.regs();
    // vendor preamble: enable INCR4/8/16 bursts (was never written).
    unsafe { r.bus_dma_ahb_ctrl().write(|w| w.bits(0x7)); }
    unsafe {
        r.bus_dma_mem_saddr().write(|w| w.bits(mem.addr()));
        r.bus_dma_flash_saddr().write(|w| w.bits(flash_addr));
        r.bus_dma_len().write(|w| w.bits(len.field()));
    }
    // dma_sel_cs: vendor forces CS1 for the DMA path. Expose as a param defaulting to CS1
    // rather than silently hardcoding the wrong value; single-flash CS0 boards override.
    unsafe { r.bus_dma_ctrl().modify(|_, w| w
        .dma_start().set_bit()
        .dma_rw().bit(read)
        .dma_sel_cs().set_bit()); } // bit4 = CS1, vendor default
    Ok(())
}

/// A flash operation address for the command path. The cmd_addr register is 30-bit,
/// so any address >= 0x4000_0000 would be silently truncated; reject it instead.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct CmdAddr(u32);
impl CmdAddr {
    pub const MAX: u32 = (1 << 30) - 1; // 0x3FFF_FFFF
    pub const fn new(addr: u32) -> Option<Self> {
        if addr <= Self::MAX { Some(CmdAddr(addr)) } else { None }
    }
    #[inline] pub const fn bits(self) -> u32 { self.0 }
}
// send_command(instruction: u8, address: Option<CmdAddr>) -- address_enable becomes
// Option presence; command_with_data takes CmdAddr. Write `r.cmd_addr().write(|w| w.bits(a.bits()))`.

/// CS setup/hold timing field (3-bit). Effective time = field+1 cycles.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct Tcss(u8); // and an identical Tcsh(u8)
impl Tcss {
    pub const fn from_field(v: u8) -> Option<Self> {
        if v <= 0x07 { Some(Tcss(v)) } else { None } // reject 8.. instead of wrapping mod 8
    }
    #[inline] pub const fn field(self) -> u32 { self.0 as u32 }
}
// configure_timing(tshsl: Tshsl, tcss: Tcss, tcsh: Tcsh) -- packs `.field()` with no mask.

/// Inter-operation delay field (4-bit). Effective time = field+2 cycles. Floored at
/// MIN_TSHSL-2 (=3) for flash tSHSL margin, but as a REJECT not a silent clamp.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct Tshsl(u8);
impl Tshsl {
    pub const MIN_FIELD: u8 = 3;  // MIN_TSHSL(5) - 2
    pub const MAX_FIELD: u8 = 15; // 4-bit
    pub const fn from_field(v: u8) -> Option<Self> {
        if v >= Self::MIN_FIELD && v <= Self::MAX_FIELD { Some(Tshsl(v)) } else { None }
    }
    #[inline] pub const fn field(self) -> u32 { self.0 as u32 }
}
// A value of 1 or 2 now returns None (caller learns its tSHSL was too short) instead of
// being silently raised to 3; 20 returns None instead of being masked to 4.

/// Per-command transfer parameters: the iftype and dummy-cycle count a dual/quad
/// instruction needs. Reuses the re-encoded SpiIfType so reserved 3/4 are unrepresentable.
#[derive(Debug, Clone, Copy)]
pub struct CmdMode {
    pub if_type: SpiIfType,   // bits [17:19] of cmd_config
    pub dummy_bytes: DummyBytes, // bits [4:6], 3-bit -> own newtype 0..=7
}
#[derive(Debug, Clone, Copy)]
pub struct DummyBytes(u8);
impl DummyBytes {
    pub const fn from_count(v: u8) -> Option<Self> { if v <= 7 { Some(DummyBytes(v)) } else { None } }
    #[inline] pub const fn field(self) -> u32 { self.0 as u32 }
}
// command_with_data(instruction, addr: CmdAddr, mode: CmdMode, write_data, read):
//   cmd_cfg |= mode.if_type.bits() << 17;  // was always 0 (Standard)
//   cmd_cfg |= mode.dummy_bytes.field() << 4; // was never set
