// Switch the full-register overwrite to a field-scoped read-modify-write, mirroring
// vendor reg32_setbits (RMW of only the target field). build_pad_ctrl stays, but is
// applied as a masked merge so unrelated bits (mode[2:0], bits7-8, >=12) survive.
const PAD_DEFINED_MASK: u32 = (0x7 << 4)/*DS*/ | (1<<3)/*ST*/ | (1<<9)|(1<<10)/*PE,PS*/ | (1<<11)/*IE*/;

fn write_pad_rmw(reg_write: impl FnOnce(u32), reg_read: impl FnOnce() -> u32,
                 drive: DriveStrength, pull: PullResistor, st: bool, ie: bool) {
    let new = build_pad_ctrl(drive, pull, st, ie);
    let old = reg_read();
    reg_write((old & !PAD_DEFINED_MASK) | (new & PAD_DEFINED_MASK));
}
