// 2) If, on-board, ROM does NOT leave the 32K ULP clock running, enable_interrupt
//    must self-enable its clock gate (class C, like PWM's configure). Provide a
//    guarded API that does the provisioning the vendor gpio_ulp_int_en documents
//    ('set ulp gpio clk as 32K') instead of only touching gpio_int_en:
impl UlpGpioPin<'_, Input> {
    /// Arm the ULP interrupt. NOTE: requires the ULP GPIO clock = 32K. On WS63 the
    /// vendor gpio_ulp_int_en body is a stub (clock is left up by ROM); confirm on
    /// silicon. If ROM does not provision it, this must also set the 32K clk gate.
    pub fn enable_interrupt(&self) {
        // TODO(board): if measured non-running, add ULP 32K clk-sel write here
        //   (self-enable own clock tree, per the PWM reference pattern).
        regs().gpio_int_en().modify(|r, w| unsafe { w.bits(r.bits() | (1 << self.bit)) });
