/// Validated ULP pin id: GPIO107..=114 → bit 0..=7. Fallible ctor (no wrap, no panic).
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct UlpPinId { bit: u8 }

impl UlpPinId {
    pub const fn from_pin(pin: u8) -> Option<Self> {
        // Bounds-check BEFORE subtraction to avoid the u8 wrap (pin<107 underflows).
        if pin < 107 || pin > 114 { return None; }
        Some(Self { bit: pin - 107 })
    }
    pub const fn number(self) -> u8 { 107 + self.bit }
    pub(crate) const fn bit(self) -> u8 { self.bit }
}

pub fn create_input_pin(id: UlpPinId) -> UlpGpioPin<'static, Input> {
    let bit = id.bit(); // already in 0..=7, no assert needed
    regs().gpio_sw_oen().modify(|r, w| unsafe { w.bits(r.bits() | (1 << bit)) });
    UlpGpioPin { bit, _mode: PhantomData }
