/// {PS,PE} pull encoding matching vendor pin_pull_t (NOT the misleading PAC doc).
/// 0=none(PE=0), 1=down(PE=1,PS=0), 2=strong-up(PE=0,PS=1), 3=up(PE=1,PS=1).
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Pull { None, Down, StrongUp, Up }

// apply_pull / build_pad_ctrl gain the strong-up arm:
let (pe, ps) = match pull {
    Pull::None => (false, false),    // 0b00
    Pull::Down => (true,  false),    // 0b01
    Pull::StrongUp => (false, true), // 0b10  (vendor value 2)
    Pull::Up => (true, true),        // 0b11
};

// Carry the live clock at construction instead of reading the const.
// Reuse the EXISTING clock_init::{TcxoFreq, SystemClocks} — do NOT invent a new clock type.
pub struct Delay { hz: u32 }
impl Delay {
    /// Build from a measured/resolved clock (probe_clocks() / init_clocks() result).
    /// pll_locked==false => CPU runs from TCXO, so use tcxo_freq, not SYSTEM_CLOCK_HZ.
    pub const fn from_clocks(c: &crate::clock_init::SystemClocks) -> Self {
        let hz = if c.pll_locked { c.cpu_clk } else { c.tcxo_freq.hz() };
        Self { hz }
    }
    /// Escape hatch with an explicit, caller-asserted Hz (40 MHz-crystal / XIP boot).
    pub const fn from_hz(hz: u32) -> Self { Self { hz } }
    /// Back-compat: assume the datasheet PLL clock. Deprecated, name the risk.
    #[deprecated = "assumes PLL locked at SYSTEM_CLOCK_HZ; use from_clocks(&probe_clocks())"]
    pub const fn new() -> Self { Self { hz: crate::soc::chip::SYSTEM_CLOCK_HZ } }
}

// The 3-cycle assumption is a measured-silicon constant, not a type-expressible bound.
// Lift it to a single named, per-chip-overridable const and document it must be
// scope-calibrated. (No newtype: there is no caller input to reject — the error is in
// the constant itself, which only a wall-clock measurement can fix.)
impl Delay {
    /// Cycles per busy-loop iteration. PROVISIONAL — measured on 240 MHz WS63 it is ~N
    /// (TODO: scope-confirm; spin_loop() lowers to a RISC-V hint with no fixed cost).
    const CYCLES_PER_LOOP: u32 = 3;
    pub fn delay_micros(&self, us: u32) {
        let cycles = (self.hz as u64 * us as u64 / 1_000_000) as u32;
        for _ in 0..(cycles / Self::CYCLES_PER_LOOP) { core::hint::spin_loop(); }
    }
}

/// eFuse access-timing calibration. Construct-time-bound to the live TCXO so the
/// reset value 0 (no working timing) is unrepresentable. Mirrors vendor
/// get_tcxo_freq()->{EFUSE_24M_CLK=0x29, EFUSE_40M_CLK=0x19}.
#[derive(Clone, Copy, PartialEq, Eq)]
pub struct EfuseClkPeriod(u8);
impl EfuseClkPeriod {
    pub const fn for_tcxo(f: crate::clock_init::TcxoFreq) -> Self {
        match f { crate::clock_init::TcxoFreq::MHz24 => Self(0x29),
                  crate::clock_init::TcxoFreq::MHz40 => Self(0x19) }
    }
    /// Detect the strap and pick the matching constant.
    pub fn detected() -> Self { Self::for_tcxo(crate::clock_init::TcxoFreq::detect()) }
    /// Escape hatch: reject 0 (the reset value = no working access timing).
    pub const fn from_raw(p: u8) -> Option<Self> { if p == 0 { None } else { Some(Self(p)) } }
    pub const fn raw(self) -> u8 { self.0 }
}
// setter takes the newtype; read_byte/write_byte should require it was set (see note).
pub fn set_clock_period(&mut self, period: EfuseClkPeriod) {
    unsafe { self.regs().efuse_clk_period().write(|w| w.bits(period.raw() as u32)); }
}

// Add the vendor's up-front whole-span check (efuse.c:74-75): (start + len) > 256 => err.
// Optionally formalize as an EfuseSpan newtype so the span is validated once at the edge.
pub struct EfuseSpan { start: u16, len: u16 }
impl EfuseSpan {
    pub const fn new(start: u16, len: u16) -> Result<Self, EfuseError> {
        match start.checked_add(len) {
            Some(end) if end <= EFUSE_MAX_BYTES => Ok(Self { start, len }),
            _ => Err(EfuseError::OutOfRange),
        }
    }
}
pub fn read_buffer(&mut self, start_byte: u16, buf: &mut [u8]) -> Result<(), EfuseError> {
    let span = EfuseSpan::new(start_byte, buf.len() as u16)?; // checked_add kills the wrap
    for (i, slot) in buf.iter_mut().enumerate() {
        *slot = self.read_byte(span.start + i as u16)?;
    }
    Ok(())
}

// 1) Take a clock-aware Delay (from the Delay fix) instead of Delay::new() so the
//    AVDD-on window is correct off-PLL. 2) Add an explicit clock precondition +
//    optional readback verify. Keep experimental.
pub fn write_byte(&mut self, addr: u16, value: u8, delay: &Delay) -> Result<(), EfuseError> {
    if addr >= EFUSE_MAX_BYTES { return Err(EfuseError::OutOfRange); }
    // ... arm write, raise AVDD ...
    delay.delay_micros(EFUSE_PROGRAM_DELAY_US);   // now timed by the REAL clock
    // ... write packed byte, lower AVDD ...
    delay.delay_micros(EFUSE_PROGRAM_DELAY_US);
    // optional: read_byte(addr) and verify the burned bits are set (vendor has no
    // erase; 0->1 only) -> EfuseError::VerifyFailed.
    Ok(())
}

/// FRO output-clock divider. Rejects the unrunnable low range that starves entropy.
/// Vendor hard-codes TRNG_INNER_FRO_DIV_CNT=0x1b (hal_trng.c:58-60); that is the
/// validated point and the reset default.
#[derive(Clone, Copy, PartialEq, Eq)]
pub struct FroDivCnt(u8);
impl FroDivCnt {
    /// The vendor's validated divider (0x1b = 27).
    pub const VENDOR: FroDivCnt = FroDivCnt(0x1b);
    /// Reject dividers below the usable floor (entropy fails the quality gate).
    pub const fn from_count(c: u8) -> Option<Self> {
        if c < MIN_FRO_DIV { None } else { Some(FroDivCnt(c)) }
    }
    pub const fn count(self) -> u8 { self.0 }
}
pub fn set_divider(&mut self, div: FroDivCnt) {
    unsafe { self.regs().trng_fro_div_cnt().write(|w| w.bits(div.count() as u32)); }
}

/// FRO sample-clock source. Vendor ALWAYS forces Inner (TRNG_INNER_FRO_CLK,
/// hal_trng.c:53-56) and never routes an external clock. External is a
/// board-provisioning precondition: keep it nameable but make Inner the obvious,
/// safe default and document the trap.
#[derive(Clone, Copy, PartialEq, Eq)]
pub enum FroSampleClock { Inner, External }
impl Default for FroSampleClock { fn default() -> Self { FroSampleClock::Inner } }
pub fn set_sample_clock(&mut self, src: FroSampleClock) {
    let bit = matches!(src, FroSampleClock::External) as u32; // 0=inner, 1=external
    unsafe { self.regs().trng_fro_sample_clk_sel().write(|w| w.bits(bit)); }
}

// Apply the vendor entropy sanity gate (hal_trng.c:111-113) before returning a word:
// reject all-zero, all-one, and two consecutive equal reads as stuck/failed entropy.
impl TrngDriver<'_> {
    fn read_checked(&self, prev: &mut Option<u32>) -> Result<u32, TrngError> {
        for _ in 0..1_000_000 {
            if self.data_ready() {
                let w = self.regs().trng_fifo_data().read().bits();
                let bad = w == 0x0000_0000 || w == 0xFFFF_FFFF || Some(w) == *prev;
                if !bad { *prev = Some(w); return Ok(w); }
                // else: stuck/degenerate sample, keep polling for a fresh word
            }
            core::hint::spin_loop();
        }
        Err(TrngError::Timeout)
    }
}
