/// Program the vendor KEYSCAN_DEFAULT_CONFIG before enable, folded into new()
/// (the under-config that leaves the strobe pulse / inter-scan wait at IP-reset 0).
/// These are FIXED vendor-default constants (no caller knob today), so no newtype is
/// warranted; they are written unconditionally in new() like pwm.rs constants.
fn apply_default_scan_timing(r: &RegisterBlock) { unsafe {
    // EVERY_ROW_PULSE_10_US, WAITING_30_AND_5_US, IDLE_3_MS_AFTER_SCAN,
    // SAMPLE_3TIMES_DEFENCE, io_de = true  (keyscan_porting.h:155-165)
    r.keyscan_pulse_time().write(|w| w.bits(PULSE_10_US));
    r.keyscan_scan_mode().write(|w| /* mode + direction */);
    r.keyscan_wait_time().write(|w| w.bits(WAIT_30_5_US));
    r.keyscan_idle_time().write(|w| w.bits(IDLE_3_MS));
    r.keyscan_ghost_key().write(|w| w.defence_num().bits(3).io_de().set_bit());
}}
// new() calls apply_default_scan_timing(r) before keyscan_enable().write(...).

/// Bring up the PDM clock the way vendor pdm_port_clock_enable(true) does, BEFORE
/// set_attr — the precondition new() currently assumes. Direct mirror of pwm.rs
/// `enable_pwm_clock()`: fixed CRG MMIO addresses, chip-gated, RMW.
fn enable_pdm_clock() {
    #[cfg(feature = "chip-bs21")]
    unsafe {
        const PDM_CLK_SEL: usize = 0x5200_004C; // bit1: 0 = XO crystal, 1 = RC osc
        const CRG_GLB_GATE: usize = 0x5200_0548; // bit10: glb_clken_pdm
        rmw(PDM_CLK_SEL, 0x1 << 1, 0);            // clear -> select precise XO
        rmw(CRG_GLB_GATE, 0, 0x1 << 10);          // open the global PDM gate
    }
}
// new() calls enable_pdm_clock() as its FIRST action, before cic_ctrl().write(...).

// Extend the existing clk_rst_en().write() in new() from 4 bits to the full vendor
// set (hal_pdm_v150.c:47-73). All are fixed enable bits / clk_freq_sel=0 — no caller
// numeric, so no newtype; just write the complete mask like the PWM CKEN field.
r.clk_rst_en().write(|w| {
    w.dmic_clken().set_bit();
    w.up_fifo_clken().set_bit();
    w.func_up_en().set_bit();
    w.func_up_ch_en_0().set_bit();
    w.cic_clken_0().set_bit();      // + CIC filter stage
    w.srcdn_clken_0().set_bit();    // + sample-rate converter
    w.hpf_clken_0().set_bit();      // + high-pass filter
    w.compd_clken_0().set_bit();    // + compensation filter
    w.ckdiv_6144k_clken().set_bit();// + 6.144 MHz master-clock divider (DMIC bit clk)
    w.saradc_clken().set_bit();
    w.clk_freq_sel().bits(0)
});
// then the existing pdm_dp_rst_n release.

// No type change for 0.5.0: there is NO caller-supplied numeric here, so no overflow
// surface. cic_gain=0x14 fits the 8-bit CicGain0W (FieldWriter<8>), srcdn_mode=0 fits
// the 2-bit SrcdnMode0W — both in range by construction. The only gap is the analog
// AFE / mic-bias / DMIC-pad board provisioning, which types cannot express.
// Action: a doc note on new() only.
/// # Board precondition
/// The DMIC data/clock pads must be muxed to PDM and (for analog AMIC) the AFE /
/// mic-bias provisioned externally; new() does not and cannot verify this.
// FUTURE (non-0.5.0): if cic_gain/srcdn_mode are ever exposed as caller knobs, wrap
// them as CicGain(u8 via from_raw, full 8-bit ok) and an SrcdnMode enum {Down2,...}.

/// Bring up the QDEC clock the way vendor qdec_clk_sel_set does, BEFORE qdec_enable
/// — folded into new() (mirror of pwm.rs enable_pwm_clock()). BS2X M_CTL addresses,
/// chip-gated, RMW + writes.
fn enable_qdec_clock() {
    #[cfg(feature = "chip-bs21")]
    unsafe {
        const QDEC_CLK_CTL: usize = 0x5200_04A0; // qdec_clk_div: num[6:0], en[7]
        const QDEC_CLK_EN_BIT: u32 = 7;
        rmw(QDEC_CLK_CTL, 0, 0x1 << QDEC_CLK_EN_BIT);     // set clock-sel-enable
        rmw(QDEC_CLK_CTL, 0x7F, FREQ_DIV /* vendor hal_qdec_freq_div */);
        // sample period (M_CTL_QDEC_SAMPLEPER_REG) — fixed vendor default for 0.5.0
        writew(QDEC_SAMPLEPER, SAMPLEPER_DEFAULT);
    }
}
// new() calls enable_qdec_clock() before r.qdec_enable().write(...).

