// Doc: "# Board precondition — encoder A/B must be wired to the QDEC pads; this fn
// muxes+pulls them but cannot verify the encoder is present."

/// Run the vendor hal_qdec_v150_init config block before clr_en/start, folded into
/// new(). All vendor-default constants (no caller knob today), written like the PWM
/// constants.
fn apply_default_qdec_config(r: &RegisterBlock) { unsafe {
    r.qdec_sampleper().write(|w| w.bits(SAMPLEPER_DEFAULT)); // else may never sample
    r.qdec_defen().write(|w| w.defen_en().set_bit().defen_num().bits(DEFEN_DEFAULT));
    r.qdec_reportper().write(|w| w.bits(REPORTPER_DEFAULT));
    r.qdec_ledcfg().write(|w| /* ledpol default */);
}}
// new() calls apply_default_qdec_config(r) before qdec_enable()/qdec_task_start().
